-- Minute Mantra — 365 Mantra Records
-- Exported from Railway MySQL production database

INSERT INTO mantras
  (day_of_year, original_script, transliteration, english_translation,
   tradition, intention, phonetic_guide, audio_filename, go_deeper_url,
   go_deeper_teaser, context_note, sacred_geometry_type)
VALUES
  (1, 'ॐ नमः शिवाय', 'Om Namah Shivaya', 'I bow to Shiva — the auspicious one, the pure consciousness within all.', 'vedic_shiva', 'Purification', 'OHM nah-MAH shih-VAH-yah', 'om_namah_shivaya.mp3', 'https://paulwagner.com', 'Why Om Namah Shivaya changes your nervous system →', 'The Panchakshara mantra — five sacred syllables representing the five elements. The most widely chanted Shaivite mantra.', 'seed_of_life'),
  (2, 'ॐ त्र्यम्बकं यजामहे', 'Om Tryambakam Yajamahe', 'We worship the three-eyed one who nourishes and liberates us from the bondage of death.', 'vedic_shiva', 'Healing', 'OHM tree-AHM-bah-kahm yah-JAH-mah-hay', 'om_tryambakam_yajama.mp3', 'https://paulwagner.com', 'The science of the Maha Mrityunjaya mantra →', 'The Maha Mrityunjaya mantra from the Rigveda. Chanted for healing, longevity, and liberation from fear.', 'seed_of_life'),
  (3, 'ॐ नमः शिवाय शुभम् शुभम् करु', 'Om Namah Shivaya Shubham Shubham Kuru', 'Om, I bow to Shiva — bring auspiciousness, bring auspiciousness.', 'vedic_shiva', 'Blessings', 'OHM nah-MAH shih-VAH-yah SHOO-bahm SHOO-bahm KOO-roo', 'om_namah_shivaya_shu.mp3', 'https://paulwagner.com', 'Morning mantras that shift your entire day →', 'An expanded form of the Panchakshara invoking blessings and positive energy into daily life.', 'lotus'),
  (4, 'शिवोऽहम् शिवोऽहम्', 'Shivo\'ham Shivo\'ham', 'I am Shiva. I am Shiva.', 'vedic_shiva', 'Self-realization', 'shih-VOH-hahm shih-VOH-hahm', 'shivoham_shivoham.mp3', 'https://paulwagner.com', 'The Nirvana Shatakam: Shankara\'s greatest poem →', 'From Adi Shankaracharya\'s Nirvana Shatakam. A direct affirmation of identity with pure consciousness.', 'sri_yantra'),
  (5, 'ॐ हौं जूं सः', 'Om Haum Jum Sah', 'Om — the seed of Shiva — the seed of life — I am that.', 'vedic_shiva', 'Vitality', 'OHM howm joom sah', 'om_haum_jum_sah.mp3', 'https://paulwagner.com', 'Bija mantras: seeds of cosmic power →', 'The Maha Mrityunjaya bija mantra. Haum is the seed syllable of Shiva; Jum is the seed of life force.', 'seed_of_life'),
  (6, 'ॐ नमः शिवाय नमः', 'Om Namah Shivaya Namah', 'Om, I bow to Shiva, I bow.', 'vedic_shiva', 'Devotion', 'OHM nah-MAH shih-VAH-yah nah-MAH', 'om_namah_shivaya_nam.mp3', 'https://paulwagner.com', 'What surrender really means in spiritual practice →', 'An extended form adding a second namah — deepening the gesture of surrender and reverence.', 'seed_of_life'),
  (7, 'ॐ शं शिवाय नमः', 'Om Sham Shivaya Namah', 'Om, I bow to Shiva who brings peace and auspiciousness.', 'vedic_shiva', 'Peace', 'OHM shahm shih-VAH-yah nah-MAH', 'om_sham_shivaya_nama.mp3', 'https://paulwagner.com', 'How mantra activates the parasympathetic nervous system →', 'Sham is the bija of peace and cooling. This mantra soothes the nervous system and calms mental agitation.', 'lotus'),
  (8, 'ॐ शिव शक्ति नमः', 'Om Shiva Shakti Namah', 'Om, I bow to the union of Shiva and Shakti — consciousness and energy.', 'vedic_shiva', 'Balance', 'OHM SHIH-vah SHAHK-tee nah-MAH', 'om_shiva_shakti_nama.mp3', 'https://paulwagner.com', 'The sacred marriage: Shiva and Shakti explained →', 'Shiva is pure awareness; Shakti is the dynamic energy of creation. Their union is the source of all existence.', 'sri_yantra'),
  (9, 'ॐ महादेवाय नमः', 'Om Mahadevaya Namah', 'Om, I bow to the Great God — the supreme deity.', 'vedic_shiva', 'Reverence', 'OHM mah-hah-DAY-vah-yah nah-MAH', 'om_mahadevaya_namah.mp3', 'https://paulwagner.com', 'The 108 names of Shiva and their meanings →', 'Mahadeva means "Great God" — one of Shiva\'s most exalted names, honoring his supremacy among the devas.', 'seed_of_life'),
  (10, 'ॐ नीलकण्ठाय नमः', 'Om Nilakanthaya Namah', 'Om, I bow to the blue-throated one who swallowed poison to save the world.', 'vedic_shiva', 'Courage', 'OHM nee-lah-KAHN-thah-yah nah-MAH', 'om_nilakanthaya_nama.mp3', 'https://paulwagner.com', 'The churning of the ocean: Shiva\'s greatest sacrifice →', 'Nilakantha — "blue throat" — refers to Shiva holding the cosmic poison in his throat to protect all beings. A mantra of fearless compassion.', 'lotus'),
  (11, 'ॐ नटराजाय नमः', 'Om Natarajaya Namah', 'Om, I bow to the Lord of the Cosmic Dance.', 'vedic_shiva', 'Flow', 'OHM nah-tah-RAH-jah-yah nah-MAH', 'om_natarajaya_namah.mp3', 'https://paulwagner.com', 'Nataraja: the physics of the cosmic dance →', 'Nataraja — Shiva as the cosmic dancer — represents the continuous cycles of creation, preservation, and dissolution.', 'flower_of_life'),
  (12, 'ॐ पशुपतये नमः', 'Om Pashupataye Namah', 'Om, I bow to the Lord of all creatures.', 'vedic_shiva', 'Compassion', 'OHM pah-shoo-PAH-tah-yay nah-MAH', 'om_pashupataye_namah.mp3', 'https://paulwagner.com', 'Shiva as the original animal protector →', 'Pashupati — "Lord of animals" — honors Shiva as the protector of all sentient beings, from the smallest creature to the greatest.', 'seed_of_life'),
  (13, 'ॐ भवाय नमः', 'Om Bhavaya Namah', 'Om, I bow to the source of all existence.', 'vedic_shiva', 'Gratitude', 'OHM bhah-VAH-yah nah-MAH', 'om_bhavaya_namah.mp3', 'https://paulwagner.com', 'The miracle of existence: why being here matters →', 'Bhava means "being" or "existence." This name honors Shiva as the ground of all being — the very fact that anything exists at all.', 'lotus'),
  (14, 'ॐ रुद्राय नमः', 'Om Rudraya Namah', 'Om, I bow to Rudra — the fierce one who removes suffering.', 'vedic_shiva', 'Release', 'OHM ROOD-rah-yah nah-MAH', 'om_rudraya_namah.mp3', 'https://paulwagner.com', 'Rudra: the sacred power of divine anger →', 'Rudra is Shiva\'s Vedic form — the howling storm god who destroys what no longer serves. Chanting this releases stuck energy.', 'sri_yantra'),
  (15, 'ॐ शंकराय नमः', 'Om Shankaraya Namah', 'Om, I bow to the one who brings blessings and auspiciousness.', 'vedic_shiva', 'Blessings', 'OHM shahn-KAH-rah-yah nah-MAH', 'om_shankaraya_namah.mp3', 'https://paulwagner.com', 'Opening to grace: the practice of receptivity →', 'Shankara — "conferring happiness" — is one of Shiva\'s most beloved names. This mantra opens the heart to receive grace.', 'seed_of_life'),
  (16, 'ॐ गिरीशाय नमः', 'Om Girishaya Namah', 'Om, I bow to the Lord of the mountains.', 'vedic_shiva', 'Stability', 'OHM gih-REE-shah-yah nah-MAH', 'om_girishaya_namah.mp3', 'https://paulwagner.com', 'Mount Kailash: the axis of the world →', 'Girisha — "mountain lord" — honors Shiva\'s home on Mount Kailash. Mountains represent the immovable foundation of consciousness.', 'lotus'),
  (17, 'ॐ भोलेनाथाय नमः', 'Om Bholenathaya Namah', 'Om, I bow to the innocent lord — the simple-hearted one.', 'vedic_shiva', 'Simplicity', 'OHM boh-lay-NAH-thah-yah nah-MAH', 'om_bholenathaya_nama.mp3', 'https://paulwagner.com', 'Why Shiva is the easiest god to please →', 'Bholenath — "innocent lord" — is a beloved folk name for Shiva. He is easily pleased by sincere devotion, however simple.', 'seed_of_life'),
  (18, 'ॐ विश्वनाथाय नमः', 'Om Vishwanathaya Namah', 'Om, I bow to the Lord of the universe.', 'vedic_shiva', 'Expansion', 'OHM vish-wah-NAH-thah-yah nah-MAH', 'om_vishwanathaya_nam.mp3', 'https://paulwagner.com', 'Varanasi: the city where Shiva never sleeps →', 'Vishwanath — "Lord of all worlds" — is the presiding deity of Varanasi, the oldest living city on earth.', 'flower_of_life'),
  (19, 'ॐ आशुतोषाय नमः', 'Om Ashutoshaya Namah', 'Om, I bow to the one who is quickly satisfied.', 'vedic_shiva', 'Contentment', 'OHM ah-shoo-TOH-shah-yah nah-MAH', 'om_ashutoshaya_namah.mp3', 'https://paulwagner.com', 'The art of contentment: Santosha in daily life →', 'Ashutosh — "quickly pleased" — teaches that Shiva asks for nothing more than sincere love. Contentment is the highest offering.', 'lotus'),
  (20, 'ॐ त्रिलोचनाय नमः', 'Om Trilochanaya Namah', 'Om, I bow to the three-eyed one who sees past, present, and future.', 'vedic_shiva', 'Clarity', 'OHM tree-loh-CHAH-nah-yah nah-MAH', 'om_trilochanaya_nama.mp3', 'https://paulwagner.com', 'Activating your third eye through mantra →', 'Shiva\'s third eye represents the eye of wisdom — the ability to see beyond duality into the nature of reality.', 'sri_yantra'),
  (21, 'ॐ सदाशिवाय नमः', 'Om Sadashivaya Namah', 'Om, I bow to the eternally auspicious one.', 'vedic_shiva', 'Eternity', 'OHM sah-dah-SHIH-vah-yah nah-MAH', 'om_sadashivaya_namah.mp3', 'https://paulwagner.com', 'What it means to touch the eternal →', 'Sadashiva — "always auspicious" — represents the eternal, unchanging aspect of Shiva beyond time and space.', 'seed_of_life'),
  (22, 'ॐ उमापतये नमः', 'Om Umapataye Namah', 'Om, I bow to the consort of Uma — the divine feminine.', 'vedic_shiva', 'Love', 'OHM oo-mah-PAH-tah-yay nah-MAH', 'om_umapataye_namah.mp3', 'https://paulwagner.com', 'Shiva and Parvati: the original love story →', 'Uma (Parvati) is Shiva\'s beloved. This mantra honors the sacred partnership of masculine and feminine principles.', 'lotus'),
  (23, 'ॐ कपर्दिने नमः', 'Om Kapardine Namah', 'Om, I bow to the matted-haired one who holds the Ganges.', 'vedic_shiva', 'Purification', 'OHM kah-pahr-DEE-nay nah-MAH', 'om_kapardine_namah.mp3', 'https://paulwagner.com', 'The Ganga in Shiva\'s hair: a story of grace →', 'Shiva\'s matted hair (jata) holds the sacred river Ganga, purifying all who touch her waters.', 'seed_of_life'),
  (24, 'ॐ भस्माङ्गाय नमः', 'Om Bhasmangaya Namah', 'Om, I bow to the one adorned with sacred ash.', 'vedic_shiva', 'Impermanence', 'OHM bahsh-MAHN-gah-yah nah-MAH', 'om_bhasmangaya_namah.mp3', 'https://paulwagner.com', 'Sacred ash and the wisdom of impermanence →', 'Shiva smears himself with ash from cremation grounds — a reminder that all bodies return to ash. This mantra cultivates non-attachment.', 'lotus'),
  (25, 'ॐ गङ्गाधराय नमः', 'Om Gangadharaya Namah', 'Om, I bow to the one who holds the sacred Ganga in his locks.', 'vedic_shiva', 'Grace', 'OHM gahn-gah-DHAH-rah-yah nah-MAH', 'om_gangadharaya_nama.mp3', 'https://paulwagner.com', 'How Shiva saved the earth with his hair →', 'When the heavenly Ganga descended to earth, Shiva caught her in his hair to prevent the earth from being destroyed by her force.', 'flower_of_life'),
  (26, 'ॐ जटाधराय नमः', 'Om Jatadharaya Namah', 'Om, I bow to the one with matted locks of an ascetic.', 'vedic_shiva', 'Renunciation', 'OHM jah-tah-DHAH-rah-yah nah-MAH', 'om_jatadharaya_namah.mp3', 'https://paulwagner.com', 'Tapas: the sacred fire of spiritual discipline →', 'The matted hair (jata) represents the renunciation of worldly vanity and the accumulation of tapas — spiritual heat.', 'seed_of_life'),
  (27, 'ॐ कालेश्वराय नमः', 'Om Kaleshwaraya Namah', 'Om, I bow to the Lord of time who transcends all time.', 'vedic_shiva', 'Presence', 'OHM kah-laysh-WAH-rah-yah nah-MAH', 'om_kaleshwaraya_nama.mp3', 'https://paulwagner.com', 'Living in the eternal now: Shiva\'s greatest teaching →', 'Kaleshwara — "Lord of time" — reminds us that Shiva is both the master of time and beyond it. This mantra anchors us in the eternal now.', 'sri_yantra'),
  (28, 'ॐ ईशानाय नमः', 'Om Ishanaya Namah', 'Om, I bow to the ruler of the northeast — the direction of grace.', 'vedic_shiva', 'Wisdom', 'OHM ee-SHAH-nah-yah nah-MAH', 'om_ishanaya_namah.mp3', 'https://paulwagner.com', 'The five faces of Shiva: Panchamukha explained →', 'Ishana is Shiva\'s form ruling the northeast direction — associated with wisdom, grace, and the transmission of spiritual knowledge.', 'lotus'),
  (29, 'ॐ तत्पुरुषाय नमः', 'Om Tatpurushaya Namah', 'Om, I bow to the supreme being — the highest self.', 'vedic_shiva', 'Self-realization', 'OHM taht-poo-ROO-shah-yah nah-MAH', 'om_tatpurushaya_nama.mp3', 'https://paulwagner.com', 'Tat tvam asi: you are that →', 'Tatpurusha — "that supreme person" — is the east-facing form of Shiva, representing the transcendent self beyond ego.', 'sri_yantra'),
  (30, 'ॐ अघोराय नमः', 'Om Aghoraya Namah', 'Om, I bow to the non-terrible one — the gentle face of Shiva.', 'vedic_shiva', 'Acceptance', 'OHM ah-GHOH-rah-yah nah-MAH', 'om_aghoraya_namah.mp3', 'https://paulwagner.com', 'The Aghori path: embracing what we fear →', 'Aghora — "not terrible" — is the south-facing form of Shiva, representing the dissolution of ego and acceptance of all aspects of existence.', 'seed_of_life'),
  (31, 'ॐ वामदेवाय नमः', 'Om Vamadevaya Namah', 'Om, I bow to the beautiful god — the graceful one.', 'vedic_shiva', 'Beauty', 'OHM vah-mah-DAY-vah-yah nah-MAH', 'om_vamadevaya_namah.mp3', 'https://paulwagner.com', 'Beauty as a spiritual path →', 'Vamadeva — "beautiful god" — is the north-facing form of Shiva, representing the creative, nurturing, and beautiful aspects of consciousness.', 'lotus'),
  (32, 'ॐ सद्योजाताय नमः', 'Om Sadyojataya Namah', 'Om, I bow to the instantly born — the creative impulse of consciousness.', 'vedic_shiva', 'Creativity', 'OHM sahd-yoh-JAH-tah-yah nah-MAH', 'om_sadyojataya_namah.mp3', 'https://paulwagner.com', 'Spontaneous creation: how inspiration really works →', 'Sadyojata — "instantly born" — is the west-facing form of Shiva, representing the spontaneous creative power of consciousness.', 'flower_of_life'),
  (33, 'ॐ हरहर महादेव', 'Om Hara Hara Mahadeva', 'Om, remove, remove — O Great God, take away all that binds me.', 'vedic_shiva', 'Liberation', 'OHM HAH-rah HAH-rah mah-hah-DAY-vah', 'om_hara_hara_mahadev.mp3', 'https://paulwagner.com', 'What Shiva removes and why you should let him →', 'Hara means "one who removes" — Shiva removes sin, suffering, and the illusion of separation. A powerful mantra of liberation.', 'sri_yantra'),
  (34, 'ॐ शिव शम्भो', 'Om Shiva Shambho', 'Om, Shiva — the self-luminous, the source of joy.', 'vedic_shiva', 'Joy', 'OHM SHIH-vah SHAHM-boh', 'om_shiva_shambho.mp3', 'https://paulwagner.com', 'Ananda: the bliss that is your true nature →', 'Shambhu — "self-luminous" or "source of happiness" — is one of Shiva\'s most joyful names. This mantra invokes pure bliss.', 'seed_of_life'),
  (35, 'ॐ नमः शिवाय गुरवे', 'Om Namah Shivaya Gurave', 'Om, I bow to Shiva who is the teacher within.', 'vedic_shiva', 'Learning', 'OHM nah-MAH shih-VAH-yah goo-RAH-vay', 'om_namah_shivaya_gur.mp3', 'https://paulwagner.com', 'The inner guru: how Shiva teaches from within →', 'The guru mantra of the Shaiva Siddhanta tradition. Shiva is the first guru — the inner teacher who guides all seekers.', 'lotus'),
  (36, 'ॐ शिवाय गुरवे नमः', 'Om Shivaya Gurave Namah', 'Om, I bow to Shiva the teacher.', 'vedic_shiva', 'Humility', 'OHM shih-VAH-yah goo-RAH-vay nah-MAH', 'om_shivaya_gurave_na.mp3', 'https://paulwagner.com', 'The Shiva Sutras: Kashmir Shaivism\'s greatest text →', 'The opening mantra of the Shiva Sutras tradition. Humility before the teacher opens the door to genuine wisdom.', 'seed_of_life'),
  (37, 'ॐ शिवाय नमः शान्तिः', 'Om Shivaya Namah Shantih', 'Om, I bow to Shiva — peace, peace, peace.', 'vedic_shiva', 'Peace', 'OHM shih-VAH-yah nah-MAH SHAHN-tih', 'om_shivaya_namah_sha.mp3', 'https://paulwagner.com', 'The three types of suffering and how to end them →', 'The triple shanti at the end of Vedic recitations removes the three types of suffering: physical, mental, and cosmic.', 'lotus'),
  (38, 'ॐ नमः शिवाय स्वाहा', 'Om Namah Shivaya Svaha', 'Om, I bow to Shiva — I offer this into the sacred fire.', 'vedic_shiva', 'Offering', 'OHM nah-MAH shih-VAH-yah svah-HAH', 'om_namah_shivaya_sva.mp3', 'https://paulwagner.com', 'Homa: the ancient practice of fire offering →', 'Svaha is the offering call of fire rituals. Adding it transforms any mantra into a complete act of surrender and offering.', 'sri_yantra'),
  (39, 'ॐ शिव ॐ शिव ॐ शिव', 'Om Shiva Om Shiva Om Shiva', 'Om Shiva, Om Shiva, Om Shiva — pure consciousness, again and again.', 'vedic_shiva', 'Absorption', 'OHM SHIH-vah OHM SHIH-vah OHM SHIH-vah', 'om_shiva_om_shiva_om.mp3', 'https://paulwagner.com', 'The power of divine name repetition →', 'Repetition of the divine name is itself the practice. Three repetitions honor the trimurti and the three states of consciousness.', 'flower_of_life'),
  (40, 'ॐ नमः शिवाय शिवाय नमः ॐ', 'Om Namah Shivaya Shivaya Namah Om', 'Om, I bow to Shiva, to Shiva I bow, Om.', 'vedic_shiva', 'Devotion', 'OHM nah-MAH shih-VAH-yah shih-VAH-yah nah-MAH OHM', 'om_namah_shivaya_shi.mp3', 'https://paulwagner.com', 'Non-duality: the teaching that changes everything →', 'A palindromic mantra — it reads the same forward and backward, representing the non-dual nature of Shiva consciousness.', 'seed_of_life'),
  (41, 'ॐ श्रीं लक्ष्म्यै नमः', 'Om Shrim Lakshmyai Namah', 'Om, with the seed of abundance, I bow to Lakshmi.', 'vedic_shakti', 'Abundance', 'OHM shreem LAHKSH-myay nah-MAH', 'mantra-041.mp3', 'https://paulwagner.com', 'Shrim: the seed sound of abundance →', 'Shrim is the bija mantra of Lakshmi — the seed vibration of abundance, beauty, and grace. Combined with her name, it invokes her full blessing.', 'lotus'),
  (42, 'ॐ शिवाय विद्महे महादेवाय धीमहि', 'Om Shivaya Vidmahe Mahadevaya Dhimahi', 'Om, may we know Shiva, may we meditate on the Great God.', 'vedic_shiva', 'Meditation', 'OHM shih-VAH-yah vid-MAH-hay mah-hah-DAY-vah-yah dhee-MAH-hee', 'om_shivaya_vidmahe_m.mp3', 'https://paulwagner.com', 'The Gayatri structure: the most powerful mantra form →', 'The Shiva Gayatri — a request for illumination through meditation on Shiva\'s supreme nature.', 'sri_yantra'),
  (43, 'ॐ महालक्ष्म्यै नमः', 'Om Mahalakshmyai Namah', 'Om, I bow to the great Lakshmi — the supreme goddess of wealth.', 'vedic_shakti', 'Prosperity', 'OHM mah-hah-LAHKSH-myay nah-MAH', 'mantra-043.mp3', 'https://paulwagner.com', 'The eight forms of Lakshmi and what they give →', 'Mahalakshmi — "great Lakshmi" — is the supreme form of the goddess who presides over all eight forms of wealth: material, spiritual, courage, progeny, victory, knowledge, food, and bliss.', 'flower_of_life'),
  (44, 'ॐ शिव तत्त्वम् अहम्', 'Om Shiva Tattvam Aham', 'Om, I am the principle of Shiva — pure consciousness.', 'vedic_shiva', 'Self-realization', 'OHM SHIH-vah TAHT-tvahm AH-hahm', 'om_shiva_tattvam_aha.mp3', 'https://paulwagner.com', 'The mahavakyas: four great sayings of the Upanishads →', 'A mahavakya-style affirmation from Kashmir Shaivism. Tattva means "that-ness" or essential principle. You are not separate from Shiva.', 'sri_yantra'),
  (45, 'ॐ नमः शिवाय नित्यम्', 'Om Namah Shivaya Nityam', 'Om, I bow to Shiva eternally — always and forever.', 'vedic_shiva', 'Commitment', 'OHM nah-MAH shih-VAH-yah NEET-yahm', 'om_namah_shivaya_nit.mp3', 'https://paulwagner.com', 'Making a spiritual vow: the power of commitment →', 'Nityam means "eternally" or "always." Adding this word transforms the mantra into a vow of perpetual devotion.', 'seed_of_life'),
  (46, 'ॐ नमो नारायणाय', 'Om Namo Narayanaya', 'Om, I bow to Narayana — the one who dwells in all beings.', 'vedic_vishnu', 'Devotion', 'OHM nah-MOH nah-rah-YAH-nah-yah', 'om_namo_narayanaya.mp3', 'https://paulwagner.com', 'Narayana: the god who lives inside you →', 'The Ashtakshara — eight-syllable mantra of Vishnu. Narayana means "the one who is the abode of all beings."', 'lotus'),
  (47, 'ॐ नमो भगवते वासुदेवाय', 'Om Namo Bhagavate Vasudevaya', 'Om, I bow to the Lord Vasudeva — the one who pervades all.', 'vedic_vishnu', 'Surrender', 'OHM nah-MOH bhah-gah-VAH-tay vah-soo-DAY-vah-yah', 'om_namo_bhagavate_va.mp3', 'https://paulwagner.com', 'The Bhagavata Purana: Vishnu\'s greatest scripture →', 'The Dvadasakshara — twelve-syllable mantra of Vishnu. Vasudeva means "the one who dwells everywhere." From the Bhagavata Purana.', 'lotus'),
  (48, 'हरे कृष्ण हरे कृष्ण', 'Hare Krishna Hare Krishna', 'O Hari, O Krishna — O divine energy, O all-attractive one.', 'vedic_vishnu', 'Joy', 'HAH-ray KRISH-nah HAH-ray KRISH-nah', 'hare_krishna_hare_kr.mp3', 'https://paulwagner.com', 'The Maha Mantra: why it works for everyone →', 'The first half of the Maha Mantra. Hare addresses the divine energy (Radha); Krishna means "all-attractive." From the Kali Santarana Upanishad.', 'flower_of_life'),
  (49, 'हरे राम हरे राम', 'Hare Rama Hare Rama', 'O Hari, O Rama — O divine energy, O the one who gives joy.', 'vedic_vishnu', 'Bliss', 'HAH-ray RAH-mah HAH-ray RAH-mah', 'hare_rama_hare_rama.mp3', 'https://paulwagner.com', 'Rama and Krishna: two faces of the same light →', 'The second half of the Maha Mantra. Rama means "the one who gives joy" or "the one in whom the yogis delight."', 'flower_of_life'),
  (50, 'ॐ श्री रामाय नमः', 'Om Shri Ramaya Namah', 'Om, I bow to the radiant Rama — the ideal of righteousness.', 'vedic_vishnu', 'Righteousness', 'OHM shree RAH-mah-yah nah-MAH', 'om_shri_ramaya_namah.mp3', 'https://paulwagner.com', 'Dharma: the path of right action →', 'Rama is the seventh avatar of Vishnu and the embodiment of dharma — right action, integrity, and noble character.', 'lotus'),
  (51, 'ॐ श्री कृष्णाय नमः', 'Om Shri Krishnaya Namah', 'Om, I bow to the radiant Krishna — the all-attractive divine.', 'vedic_vishnu', 'Love', 'OHM shree KRISH-nah-yah nah-MAH', 'om_shri_krishnaya_na.mp3', 'https://paulwagner.com', 'The Bhagavad Gita in one sentence →', 'Krishna is the eighth avatar of Vishnu and the teacher of the Bhagavad Gita. His name means "all-attractive" or "dark one."', 'lotus'),
  (52, 'ॐ विष्णवे नमः', 'Om Vishnave Namah', 'Om, I bow to Vishnu — the all-pervading one.', 'vedic_vishnu', 'Omnipresence', 'OHM VISH-nah-vay nah-MAH', 'om_vishnave_namah.mp3', 'https://paulwagner.com', 'How to feel the divine presence everywhere →', 'Vishnu means "the all-pervading one" — the divine presence that permeates every atom of creation.', 'flower_of_life'),
  (53, 'ॐ कमलवासिन्यै नमः', 'Om Kamalavासinyai Namah', 'Om, I bow to the one who dwells in the lotus.', 'vedic_shakti', 'Purity', 'OHM kah-mah-lah-VAH-sin-yay nah-MAH', 'mantra-053.mp3', 'https://paulwagner.com', 'Why Lakshmi sits on a lotus →', 'Kamalavasini — "dweller in the lotus" — Lakshmi sits on a lotus that rises from muddy water yet remains pure. She teaches that true wealth is untouched by worldly corruption.', 'lotus'),
  (54, 'ॐ श्रीं ह्रीं श्रीं लक्ष्मी', 'Om Shrim Hrim Shrim Lakshmi', 'Om — abundance, heart, abundance — Lakshmi.', 'vedic_shakti', 'Heart Wealth', 'OHM shreem hreem shreem LAHK-shmee', 'mantra-054.mp3', 'https://paulwagner.com', 'The bija mantras of the heart and wealth →', 'A powerful combination of Lakshmi bija mantras. Shrim invokes abundance; Hrim opens the heart. Together they attract wealth that flows from love.', 'sri_yantra'),
  (55, 'ॐ ऐश्वर्यलक्ष्म्यै नमः', 'Om Aishwaryalakshmyai Namah', 'Om, I bow to Lakshmi of sovereignty and divine wealth.', 'vedic_shakti', 'Sovereignty', 'OHM aysh-wahr-yah-LAHKSH-myay nah-MAH', 'mantra-055.mp3', 'https://paulwagner.com', 'Aishwarya: the wealth that is inner sovereignty →', 'Aishwarya Lakshmi is one of the Ashta Lakshmi — the eight forms. She represents not material wealth but the sovereignty of the self — the wealth of being your own master.', 'flower_of_life'),
  (56, 'ॐ जय जगदीश हरे', 'Om Jai Jagadish Hare', 'Om, victory to the Lord of the universe who removes all suffering.', 'vedic_vishnu', 'Victory', 'OHM jay jah-gah-DEESH HAH-ray', 'om_jai_jagadish_hare.mp3', 'https://paulwagner.com', 'Aarti: the ritual of light and devotion →', 'From the beloved Aarti prayer sung at Vishnu temples across India. Jagadish means "Lord of the world."', 'lotus'),
  (57, 'ॐ श्री विष्णवे नमः', 'Om Shri Vishnave Namah', 'Om, I bow to the radiant, all-pervading Vishnu.', 'vedic_vishnu', 'Abundance', 'OHM shree VISH-nah-vay nah-MAH', 'om_shri_vishnave_nam.mp3', 'https://paulwagner.com', 'Lakshmi and Vishnu: the divine couple of abundance →', 'Shri (Lakshmi) is Vishnu\'s consort. Invoking both together brings the fullness of divine grace — both consciousness and abundance.', 'lotus'),
  (58, 'ॐ हरये नमः', 'Om Haraye Namah', 'Om, I bow to Hari — the one who removes all suffering.', 'vedic_vishnu', 'Relief', 'OHM HAH-rah-yay nah-MAH', 'om_haraye_namah.mp3', 'https://paulwagner.com', 'How Vishnu removes suffering: the path of grace →', 'Hari means "the remover" — Vishnu removes the three types of suffering: physical, mental, and karmic.', 'flower_of_life'),
  (59, 'ॐ केशवाय नमः', 'Om Keshavaya Namah', 'Om, I bow to Keshava — the one with beautiful hair.', 'vedic_vishnu', 'Beauty', 'OHM kay-SHAH-vah-yah nah-MAH', 'om_keshavaya_namah.mp3', 'https://paulwagner.com', 'The 1000 names of Vishnu: the Vishnu Sahasranama →', 'Keshava — "beautiful-haired" or "slayer of Keshi" — is one of Krishna\'s most beloved names. Beauty is a form of the divine.', 'lotus'),
  (60, 'ॐ माधवाय नमः', 'Om Madhavaya Namah', 'Om, I bow to Madhava — the lord of spring, the sweet one.', 'vedic_vishnu', 'Sweetness', 'OHM mah-DHAH-vah-yah nah-MAH', 'om_madhavaya_namah.mp3', 'https://paulwagner.com', 'Madhurya bhava: the sweetness of divine love →', 'Madhava means "spring" or "sweet" — Krishna as the embodiment of sweetness, beauty, and the joy of creation.', 'lotus'),
  (61, 'ॐ गोविन्दाय नमः', 'Om Govindaya Namah', 'Om, I bow to Govinda — the protector of cows and the earth.', 'vedic_vishnu', 'Protection', 'OHM goh-VIN-dah-yah nah-MAH', 'om_govindaya_namah.mp3', 'https://paulwagner.com', 'Vrindavan: the sacred forest of Krishna\'s childhood →', 'Govinda — "protector of cows" — is one of Krishna\'s most beloved names, honoring his childhood as a cowherd in Vrindavan.', 'flower_of_life'),
  (62, 'ॐ विष्णवे नमः त्रिविक्रमाय', 'Om Vishnave Namah Trivikramaya', 'Om, I bow to Vishnu who took three steps to encompass the universe.', 'vedic_vishnu', 'Expansion', 'OHM VISH-nah-vay nah-MAH tree-vik-RAH-mah-yah', 'om_vishnave_namah_tr.mp3', 'https://paulwagner.com', 'Vamana: the dwarf who became the universe →', 'Trivikrama — "three steps" — refers to Vamana avatar who measured the entire universe in three strides. Consciousness is boundless.', 'flower_of_life'),
  (63, 'ॐ अच्युताय नमः', 'Om Achyutaya Namah', 'Om, I bow to the infallible one who never falls.', 'vedic_vishnu', 'Steadiness', 'OHM ah-CHYOO-tah-yah nah-MAH', 'om_achyutaya_namah.mp3', 'https://paulwagner.com', 'Steadiness in the storm: Arjuna\'s lesson →', 'Achyuta — "infallible" or "imperishable" — is one of Krishna\'s names in the Bhagavad Gita. The divine never wavers.', 'lotus'),
  (64, 'ॐ अनन्ताय नमः', 'Om Anantaya Namah', 'Om, I bow to the infinite, endless one.', 'vedic_vishnu', 'Infinity', 'OHM ah-NAHN-tah-yah nah-MAH', 'om_anantaya_namah.mp3', 'https://paulwagner.com', 'Ananta Shesha: the serpent of eternity →', 'Ananta — "infinite" — is both a name of Vishnu and the cosmic serpent on which he rests. Infinity is the ground of all existence.', 'flower_of_life'),
  (65, 'ॐ पुण्डरीकाक्षाय नमः', 'Om Pundarikakshaya Namah', 'Om, I bow to the lotus-eyed one.', 'vedic_vishnu', 'Purity', 'OHM poon-dah-ree-KAH-kshah-yah nah-MAH', 'om_pundarikakshaya_n.mp3', 'https://paulwagner.com', 'The lotus: growing pure in an impure world →', 'Pundarikaksha — "lotus-eyed" — describes Vishnu\'s eyes as pure as lotus flowers. The lotus grows in mud but remains unstained.', 'lotus'),
  (66, 'ॐ श्रीधराय नमः', 'Om Shridharaya Namah', 'Om, I bow to the one who holds Shri — the divine abundance.', 'vedic_vishnu', 'Abundance', 'OHM shree-DHAH-rah-yah nah-MAH', 'om_shridharaya_namah.mp3', 'https://paulwagner.com', 'Lakshmi on Vishnu\'s chest: the secret of abundance →', 'Sridhara — "holder of Shri" — honors Vishnu as the one who sustains Lakshmi, the goddess of abundance, on his chest.', 'lotus'),
  (67, 'ॐ हृषीकेशाय नमः', 'Om Hrishikeshaya Namah', 'Om, I bow to the lord of the senses.', 'vedic_vishnu', 'Mastery', 'OHM hrish-ee-KAY-shah-yah nah-MAH', 'om_hrishikeshaya_nam.mp3', 'https://paulwagner.com', 'Mastery of the senses: the Bhagavad Gita\'s teaching →', 'Hrishikesha — "lord of the senses" — is the name Arjuna uses when asking Krishna to be his charioteer in the Bhagavad Gita.', 'flower_of_life'),
  (68, 'ॐ पद्मनाभाय नमः', 'Om Padmanabhaya Namah', 'Om, I bow to the one with a lotus in his navel — the source of creation.', 'vedic_vishnu', 'Creation', 'OHM pahd-mah-NAH-bhah-yah nah-MAH', 'om_padmanabhaya_nama.mp3', 'https://paulwagner.com', 'The cosmic navel: creation from the center →', 'From Vishnu\'s navel grows a lotus, and from that lotus emerges Brahma, the creator. The navel is the center of creative power.', 'lotus'),
  (69, 'ॐ दामोदराय नमः', 'Om Damodaraya Namah', 'Om, I bow to Damodara — the one bound by love.', 'vedic_vishnu', 'Love', 'OHM dah-moh-DAH-rah-yah nah-MAH', 'om_damodaraya_namah.mp3', 'https://paulwagner.com', 'How love binds even God: the Damodara story →', 'Damodara — "rope around the belly" — refers to Krishna being tied by his mother Yashoda. Love is the only force that can bind the infinite.', 'lotus'),
  (70, 'ॐ सङ्कर्षणाय नमः', 'Om Sankarshanaya Namah', 'Om, I bow to Sankarshana — the one who draws all toward the divine.', 'vedic_vishnu', 'Attraction', 'OHM sahn-kar-SHAH-nah-yah nah-MAH', 'om_sankarshanaya_nam.mp3', 'https://paulwagner.com', 'The four vyuhas: Vishnu\'s cosmic emanations →', 'Sankarshana is one of the four vyuha (emanation) forms of Vishnu, representing the attractive power of divine love.', 'flower_of_life'),
  (71, 'ॐ प्रद्युम्नाय नमः', 'Om Pradyumnaya Namah', 'Om, I bow to Pradyumna — the supremely luminous one.', 'vedic_vishnu', 'Radiance', 'OHM prahd-YOOM-nah-yah nah-MAH', 'om_pradyumnaya_namah.mp3', 'https://paulwagner.com', 'The luminous mind: how consciousness illuminates →', 'Pradyumna — "supremely luminous" — is the son of Krishna and Rukmini, representing the mind aspect of the divine.', 'lotus'),
  (72, 'ॐ अनिरुद्धाय नमः', 'Om Aniruddhaya Namah', 'Om, I bow to Aniruddha — the unstoppable one.', 'vedic_vishnu', 'Unstoppability', 'OHM ah-nee-ROOD-dhah-yah nah-MAH', 'om_aniruddhaya_namah.mp3', 'https://paulwagner.com', 'Your unstoppable nature: removing inner obstacles →', 'Aniruddha — "unstoppable" — represents the ego aspect of the divine that cannot be obstructed. Your true nature cannot be stopped.', 'flower_of_life'),
  (73, 'ॐ पुरुषोत्तमाय नमः', 'Om Purushottamaya Namah', 'Om, I bow to the supreme person — the highest self.', 'vedic_vishnu', 'Excellence', 'OHM poo-roo-SHOH-tah-mah-yah nah-MAH', 'om_purushottamaya_na.mp3', 'https://paulwagner.com', 'The three purushhas: Gita chapter 15 explained →', 'Purushottama — "supreme person" — is described in the 15th chapter of the Bhagavad Gita as the highest reality beyond both the perishable and imperishable.', 'lotus'),
  (74, 'ॐ विश्वम्भराय नमः', 'Om Vishwambharaya Namah', 'Om, I bow to the one who sustains the entire universe.', 'vedic_vishnu', 'Trust', 'OHM vish-wahm-BHAH-rah-yah nah-MAH', 'om_vishwambharaya_na.mp3', 'https://paulwagner.com', 'Trusting the intelligence that runs the universe →', 'Vishwambhara — "sustainer of the universe" — reminds us that the same intelligence sustaining the cosmos is sustaining you.', 'flower_of_life'),
  (75, 'ॐ जनार्दनाय नमः', 'Om Janardanaya Namah', 'Om, I bow to the one who gives joy to all people.', 'vedic_vishnu', 'Service', 'OHM jah-nahr-DAH-nah-yah nah-MAH', 'om_janardanaya_namah.mp3', 'https://paulwagner.com', 'Seva: the yoga of selfless service →', 'Janardana — "one who gives joy to people" — is the name used when Krishna acts as the divine servant of humanity.', 'lotus'),
  (76, 'ॐ उपेन्द्राय नमः', 'Om Upendraya Namah', 'Om, I bow to Upendra — the younger brother of Indra.', 'vedic_vishnu', 'Humility', 'OHM oo-PEN-drah-yah nah-MAH', 'om_upendraya_namah.mp3', 'https://paulwagner.com', 'The power of appearing small: Vamana\'s teaching →', 'Upendra — "junior Indra" — refers to Vamana avatar. The infinite chose to appear as the smallest, most humble form to teach the greatest lesson.', 'lotus'),
  (77, 'ॐ वामनाय नमः', 'Om Vamanaya Namah', 'Om, I bow to Vamana — the dwarf avatar who measured the cosmos.', 'vedic_vishnu', 'Humility', 'OHM vah-MAH-nah-yah nah-MAH', 'om_vamanaya_namah.mp3', 'https://paulwagner.com', 'Small appearances, infinite reality →', 'Vamana took three steps to measure earth, sky, and heaven — teaching that the infinite can appear in the smallest form.', 'flower_of_life'),
  (78, 'ॐ श्रीनिवासाय नमः', 'Om Shrinivasaya Namah', 'Om, I bow to Shrinivasa — the abode of Shri (Lakshmi).', 'vedic_vishnu', 'Abundance', 'OHM shree-nih-VAH-sah-yah nah-MAH', 'om_shrinivasaya_nama.mp3', 'https://paulwagner.com', 'Tirupati: why 100,000 people visit every day →', 'Shrinivasa — "dwelling place of Shri" — is the name of Vishnu at Tirupati, the most visited temple in the world.', 'lotus'),
  (79, 'ॐ रङ्गनाथाय नमः', 'Om Ranganathaya Namah', 'Om, I bow to Ranganatha — the lord of the stage of creation.', 'vedic_vishnu', 'Presence', 'OHM rahn-gah-NAH-thah-yah nah-MAH', 'om_ranganathaya_nama.mp3', 'https://paulwagner.com', 'Srirangam: the largest functioning temple in the world →', 'Ranganatha — "lord of the stage" — is Vishnu reclining on Ananta at Srirangam. The universe is his stage; we are his players.', 'lotus'),
  (80, 'ॐ वेङ्कटेशाय नमः', 'Om Venkatesaya Namah', 'Om, I bow to Venkatesa — the lord of Venkata hill.', 'vedic_vishnu', 'Grace', 'OHM ven-kah-TAY-shah-yah nah-MAH', 'om_venkatesaya_namah.mp3', 'https://paulwagner.com', 'The seven hills of Tirupati and their meaning →', 'Venkatesa is Vishnu at Tirumala-Tirupati. Venkata means "destroyer of sins." This mantra is believed to grant all desires.', 'lotus'),
  (81, 'ॐ गोपालाय नमः', 'Om Gopalaya Namah', 'Om, I bow to Gopala — the protector of cows and souls.', 'vedic_vishnu', 'Nurturing', 'OHM goh-PAH-lah-yah nah-MAH', 'om_gopalaya_namah.mp3', 'https://paulwagner.com', 'The cow in Vedic tradition: why she is sacred →', 'Gopala — "protector of cows" — is Krishna as the divine cowherd who tenderly cares for all beings under his protection.', 'flower_of_life'),
  (82, 'ॐ मुकुन्दाय नमः', 'Om Mukundaya Namah', 'Om, I bow to Mukunda — the giver of liberation.', 'vedic_vishnu', 'Liberation', 'OHM moo-KOON-dah-yah nah-MAH', 'om_mukundaya_namah.mp3', 'https://paulwagner.com', 'Mukti: the four types of liberation in Vedanta →', 'Mukunda — "giver of mukti (liberation)" — is one of Krishna\'s most powerful names. Chanting it is said to dissolve karmic bondage.', 'lotus'),
  (83, 'ॐ मधुसूदनाय नमः', 'Om Madhusudanaya Namah', 'Om, I bow to Madhusudhana — the slayer of the demon Madhu.', 'vedic_vishnu', 'Courage', 'OHM mah-dhoo-SOO-dah-nah-yah nah-MAH', 'om_madhusudanaya_nam.mp3', 'https://paulwagner.com', 'The inner demons: what Vishnu really slays →', 'Madhusudhana — "slayer of Madhu" — refers to Vishnu defeating the demon of delusion. This mantra destroys inner demons of doubt and fear.', 'flower_of_life'),
  (84, 'ॐ त्रिविक्रमाय नमः', 'Om Trivikramaya Namah', 'Om, I bow to Trivikrama — the one who strode across the three worlds.', 'vedic_vishnu', 'Expansion', 'OHM tree-vik-RAH-mah-yah nah-MAH', 'om_trivikramaya_nama.mp3', 'https://paulwagner.com', 'The three worlds and how to inhabit them all →', 'Trivikrama\'s three steps represent past, present, and future — or earth, atmosphere, and heaven. Consciousness encompasses all.', 'flower_of_life'),
  (85, 'ॐ वराहाय नमः', 'Om Varahaya Namah', 'Om, I bow to Varaha — the boar avatar who rescued the earth.', 'vedic_vishnu', 'Rescue', 'OHM vah-RAH-hah-yah nah-MAH', 'om_varahaya_namah.mp3', 'https://paulwagner.com', 'The Varaha avatar: diving into darkness to save the earth →', 'Varaha lifted the earth from the cosmic ocean on his tusks. This mantra invokes the power to rescue what is precious from darkness.', 'lotus'),
  (86, 'ॐ नृसिंहाय नमः', 'Om Nrisimhaya Namah', 'Om, I bow to Narasimha — the man-lion who protects devotees.', 'vedic_vishnu', 'Protection', 'OHM nree-SIM-hah-yah nah-MAH', 'om_nrisimhaya_namah.mp3', 'https://paulwagner.com', 'Prahlada\'s faith: the devotee who couldn\'t be killed →', 'Narasimha burst from a pillar to protect Prahlada — teaching that the divine is present everywhere, in every atom, at every moment.', 'flower_of_life'),
  (87, 'ॐ परशुरामाय नमः', 'Om Parashuramaya Namah', 'Om, I bow to Parashurama — the warrior sage with the axe.', 'vedic_vishnu', 'Justice', 'OHM pah-rah-shoo-RAH-mah-yah nah-MAH', 'om_parashuramaya_nam.mp3', 'https://paulwagner.com', 'When compassion requires fierceness →', 'Parashurama — "Rama with the axe" — is the sixth avatar who restored cosmic justice. Sometimes fierce action is the most compassionate response.', 'lotus'),
  (88, 'ॐ बलराम नमोऽस्तु ते', 'Om Balarama Namostu Te', 'Om, I bow to Balarama — the strong one, Krishna\'s elder brother.', 'vedic_vishnu', 'Strength', 'OHM bah-lah-RAH-mah nah-MOHS-too tay', 'om_balarama_namostu.mp3', 'https://paulwagner.com', 'Balarama: the strength behind Krishna\'s play →', 'Balarama — "strong Rama" — is the eighth avatar, representing the strength that supports and protects the divine play of consciousness.', 'flower_of_life'),
  (89, 'ॐ कल्किने नमः', 'Om Kalkine Namah', 'Om, I bow to Kalki — the future avatar who restores righteousness.', 'vedic_vishnu', 'Hope', 'OHM KAHL-kih-nay nah-MAH', 'om_kalkine_namah.mp3', 'https://paulwagner.com', 'The Kali Yuga: are we living in the dark age? →', 'Kalki is the tenth and final avatar, yet to come — riding a white horse to restore dharma at the end of the Kali Yuga.', 'lotus'),
  (90, 'ॐ दशावताराय नमः', 'Om Dashavataraaya Namah', 'Om, I bow to the ten avatars — the divine in all its forms.', 'vedic_vishnu', 'Wholeness', 'OHM dah-shah-vah-TAH-rah-yah nah-MAH', 'om_dashavataraaya_na.mp3', 'https://paulwagner.com', 'Darwin and the Dashavatara: evolution in the Vedas →', 'The ten avatars of Vishnu trace the evolution of consciousness from fish to human — a map of spiritual evolution across cosmic time.', 'flower_of_life'),
  (91, 'ॐ ऐं ह्रीं क्लीं', 'Om Aim Hrim Klim', 'Om — the seed of Saraswati, Lakshmi, and Kali — wisdom, abundance, and transformation.', 'vedic_shakti', 'Empowerment', 'OHM AIM hreem kleem', 'om_aim_hrim_klim.mp3', 'https://paulwagner.com', 'The three great goddesses and their bija mantras →', 'Three bija mantras of the divine feminine: Aim (Saraswati/wisdom), Hrim (Lakshmi/heart), Klim (Kali/transformation). Together they invoke the full power of Shakti.', 'sri_yantra'),
  (92, 'ॐ दुर्गायै नमः', 'Om Durgayai Namah', 'Om, I bow to Durga — the invincible one who protects.', 'vedic_shakti', 'Protection', 'OHM door-GAH-yay nah-MAH', 'om_durgayai_namah.mp3', 'https://paulwagner.com', 'Durga\'s nine forms: the Navadurga →', 'Durga — "the invincible" or "the one who is difficult to approach" — is the warrior goddess who defeats all forms of evil and ignorance.', 'sri_yantra'),
  (93, 'ॐ काल्यै नमः', 'Om Kalyai Namah', 'Om, I bow to Kali — the dark mother who liberates through transformation.', 'vedic_shakti', 'Transformation', 'OHM KAH-lyay nah-MAH', 'om_kalyai_namah.mp3', 'https://paulwagner.com', 'Kali: the goddess who loves you enough to destroy your ego →', 'Kali — "the dark one" or "time" — is the most powerful form of Shakti. She destroys ego and illusion to reveal the eternal self beneath.', 'sri_yantra'),
  (94, 'ॐ श्रीं ह्रीं श्रीं', 'Om Shrim Hrim Shrim', 'Om — Lakshmi\'s seed — the heart — Lakshmi\'s seed again.', 'vedic_shakti', 'Abundance', 'OHM shreem hreem shreem', 'om_shrim_hrim_shrim.mp3', 'https://paulwagner.com', 'Lakshmi\'s eight forms: the Ashtalakshmi →', 'Shrim is Lakshmi\'s bija — the seed of abundance, beauty, and grace. Hrim is the heart bija. Together they open the heart to receive.', 'lotus'),
  (95, 'ॐ ऐं सरस्वत्यै नमः', 'Om Aim Saraswatyai Namah', 'Om, with the seed of wisdom, I bow to Saraswati.', 'vedic_shakti', 'Wisdom', 'OHM AIM sah-rahs-WAHT-yay nah-MAH', 'om_aim_saraswatyai_n.mp3', 'https://paulwagner.com', 'Saraswati\'s four arms: the tools of wisdom →', 'Saraswati — "the flowing one" — is the goddess of wisdom, learning, music, and the arts. Aim is her bija, activating the intellect.', 'lotus'),
  (96, 'ॐ श्रीं महालक्ष्म्यै नमः', 'Om Shrim Mahalakshmyai Namah', 'Om, I bow to the great Lakshmi — the goddess of all abundance.', 'vedic_shakti', 'Prosperity', 'OHM shreem mah-hah-LAHK-shmyay nah-MAH', 'om_shrim_mahalakshmy.mp3', 'https://paulwagner.com', 'The eight forms of Lakshmi and what they offer →', 'Mahalakshmi — "great Lakshmi" — is the supreme form of the goddess of abundance, encompassing all eight forms of wealth.', 'lotus'),
  (97, 'ॐ क्लीं काल्यै नमः', 'Om Klim Kalyai Namah', 'Om, with the seed of transformation, I bow to Kali.', 'vedic_shakti', 'Release', 'OHM kleem KAH-lyay nah-MAH', 'om_klim_kalyai_namah.mp3', 'https://paulwagner.com', 'What Kali wants you to release →', 'Klim is the bija of attraction and transformation. Combined with Kali\'s name, it invokes the power to release what no longer serves.', 'sri_yantra'),
  (98, 'ॐ चण्डिकायै नमः', 'Om Chandikayai Namah', 'Om, I bow to Chandika — the fierce, passionate one.', 'vedic_shakti', 'Passion', 'OHM chahn-dee-KAH-yay nah-MAH', 'om_chandikayai_namah.mp3', 'https://paulwagner.com', 'The Devi Mahatmya: the goddess\'s greatest battle →', 'Chandika is the fierce form of Durga from the Devi Mahatmya. She embodies the passionate, unstoppable force of the divine feminine.', 'sri_yantra'),
  (99, 'ॐ त्रिपुरसुन्दर्यै नमः', 'Om Tripurasundaryai Namah', 'Om, I bow to Tripurasundari — the beauty of the three worlds.', 'vedic_shakti', 'Beauty', 'OHM tree-poo-rah-soon-DAH-ryay nah-MAH', 'om_tripurasundaryai.mp3', 'https://paulwagner.com', 'Sri Vidya: the highest Shakta tradition →', 'Tripurasundari — "beautiful in the three worlds" — is the supreme goddess of the Sri Vidya tradition, presiding over the Sri Yantra.', 'sri_yantra'),
  (100, 'ॐ भुवनेश्वर्यै नमः', 'Om Bhuvaneshwaryai Namah', 'Om, I bow to Bhuvaneshwari — the queen of the universe.', 'vedic_shakti', 'Sovereignty', 'OHM bhoo-vah-naysh-WAH-ryay nah-MAH', 'om_bhuvaneshwaryai_n.mp3', 'https://paulwagner.com', 'The ten Mahavidyas: the wisdom goddesses →', 'Bhuvaneshwari — "queen of the universe" — is the fourth of the ten Mahavidyas, representing the vast space of consciousness.', 'sri_yantra'),
  (101, 'ॐ भैरव्यै नमः', 'Om Bhairavyai Namah', 'Om, I bow to Bhairavi — the fierce, terrifying goddess of liberation.', 'vedic_shakti', 'Fearlessness', 'OHM bhay-RAH-vyay nah-MAH', 'om_bhairavyai_namah.mp3', 'https://paulwagner.com', 'What we fear and why the goddess is not it →', 'Bhairavi — "the terrifying one" — is the fifth Mahavidya. Her terror is only for the ego; to the true self, she is pure love.', 'sri_yantra'),
  (102, 'ॐ छिन्नमस्तायै नमः', 'Om Chhinnamastayai Namah', 'Om, I bow to Chhinnamasta — the self-decapitated goddess of sacrifice.', 'vedic_shakti', 'Sacrifice', 'OHM chhin-nah-MAHS-tah-yay nah-MAH', 'om_chhinnamastayai_n.mp3', 'https://paulwagner.com', 'The mystery of Chhinnamasta: love beyond the ego →', 'Chhinnamasta holds her own severed head, feeding her devotees with her blood. She teaches that the highest love is total self-giving.', 'sri_yantra'),
  (103, 'ॐ धूमावत्यै नमः', 'Om Dhumavatyai Namah', 'Om, I bow to Dhumavati — the smoky widow goddess of dissolution.', 'vedic_shakti', 'Acceptance', 'OHM dhoo-mah-VAH-tyay nah-MAH', 'om_dhumavatyai_namah.mp3', 'https://paulwagner.com', 'The wisdom of emptiness: Dhumavati\'s gift →', 'Dhumavati — "the smoky one" — represents the void after dissolution. She teaches acceptance of loss, old age, and the wisdom of emptiness.', 'sri_yantra'),
  (104, 'ॐ बगलामुख्यै नमः', 'Om Bagalamukhai Namah', 'Om, I bow to Bagalamukhi — the crane-faced goddess who paralyzes enemies.', 'vedic_shakti', 'Power', 'OHM bah-gah-lah-MOOK-hyay nah-MAH', 'om_bagalamukhai_nama.mp3', 'https://paulwagner.com', 'Bagalamukhi: the goddess who silences enemies →', 'Bagalamukhi — "crane-faced" — is the eighth Mahavidya who paralyzes negative forces. She stills the tongue of slander and the mind of confusion.', 'sri_yantra'),
  (105, 'ॐ मातङ्ग्यै नमः', 'Om Matangyai Namah', 'Om, I bow to Matangi — the outcast goddess of inner wisdom.', 'vedic_shakti', 'Authenticity', 'OHM mah-TAHN-gyay nah-MAH', 'om_matangyai_namah.mp3', 'https://paulwagner.com', 'Matangi: the wisdom of the outcast →', 'Matangi — the "outcast" or "elephant" goddess — is the ninth Mahavidya, representing wisdom that comes from outside conventional boundaries.', 'lotus'),
  (106, 'ॐ कमलायै नमः', 'Om Kamalayai Namah', 'Om, I bow to Kamala — the lotus goddess, the tantric Lakshmi.', 'vedic_shakti', 'Grace', 'OHM kah-mah-LAH-yay nah-MAH', 'om_kamalayai_namah.mp3', 'https://paulwagner.com', 'The ten Mahavidyas: a complete map of divine feminine power →', 'Kamala — "lotus" — is the tenth Mahavidya, the tantric form of Lakshmi. She represents the fullness of grace and the beauty of pure consciousness.', 'lotus'),
  (107, 'ॐ तारायै नमः', 'Om Tarayai Namah', 'Om, I bow to Tara — the star goddess who guides across the ocean of existence.', 'vedic_shakti', 'Guidance', 'OHM TAH-rah-yay nah-MAH', 'om_tarayai_namah.mp3', 'https://paulwagner.com', 'Tara: the goddess shared by Hinduism and Buddhism →', 'Tara — "star" or "one who saves" — is the second Mahavidya and also a major Buddhist deity. She guides souls across the ocean of samsara.', 'star_of_life'),
  (108, 'ॐ ऐं ह्रीं श्रीं त्रिपुर सुन्दरी', 'Om Aim Hrim Shrim Tripura Sundari', 'Om — wisdom, heart, abundance — beauty of the three worlds.', 'vedic_shakti', 'Completeness', 'OHM AIM hreem shreem tree-POO-rah soon-DAH-ree', 'om_aim_hrim_shrim_tr.mp3', 'https://paulwagner.com', 'Why 108 is the most sacred number →', 'Day 108 — the sacred number of the mala. This mantra combines the three great bija mantras with the supreme goddess of the Sri Yantra.', 'sri_yantra'),
  (109, 'ॐ नमो देव्यै महादेव्यै', 'Om Namo Devyai Mahadevyai', 'Om, I bow to the goddess, the great goddess.', 'vedic_shakti', 'Reverence', 'OHM nah-MOH DAY-vyay mah-hah-DAY-vyay', 'om_namo_devyai_mahad.mp3', 'https://paulwagner.com', 'The Devi Mahatmya: 700 verses of goddess power →', 'The opening invocation of the Devi Mahatmya — the most sacred text of the Shakta tradition, celebrating the goddess\'s cosmic victory.', 'sri_yantra'),
  (110, 'या देवी सर्वभूतेषु', 'Ya Devi Sarvabhuteshu', 'The goddess who dwells in all beings...', 'vedic_shakti', 'Omnipresence', 'yah DAY-vee sahr-vah-BHOO-tay-shoo', 'ya_devi_sarvabhutesh.mp3', 'https://paulwagner.com', 'The goddess in all forms: the Devi Mahatmya\'s teaching →', 'From the Devi Mahatmya. The full verse continues: "...in the form of consciousness, power, peace, faith, beauty, activity, memory, compassion, and error — I bow to her."', 'flower_of_life'),
  (111, 'नमस्तस्यै नमस्तस्यै नमस्तस्यै नमो नमः', 'Namastasyai Namastasyai Namastasyai Namo Namah', 'I bow to her, I bow to her, I bow to her, I bow.', 'vedic_shakti', 'Surrender', 'nah-mahs-TAHS-yay nah-mahs-TAHS-yay nah-mahs-TAHS-yay nah-MOH nah-MAH', 'namastasyai_namastas.mp3', 'https://paulwagner.com', 'The power of triple repetition in mantra →', 'The refrain of the Devi Mahatmya. Triple repetition of surrender to the goddess — a complete act of devotion.', 'sri_yantra'),
  (112, 'ॐ शक्ति शक्ति शक्ति', 'Om Shakti Shakti Shakti', 'Om, power, power, power — the divine feminine energy.', 'vedic_shakti', 'Power', 'OHM SHAHK-tee SHAHK-tee SHAHK-tee', 'om_shakti_shakti_sha.mp3', 'https://paulwagner.com', 'Kundalini Shakti: the sleeping serpent power →', 'Shakti is the primordial energy of the universe — the force that animates all of creation. This mantra awakens your own inner Shakti.', 'sri_yantra'),
  (113, 'ॐ जय माँ', 'Om Jai Maa', 'Om, victory to the Divine Mother.', 'vedic_shakti', 'Devotion', 'OHM jay MAH', 'om_jai_maa.mp3', 'https://paulwagner.com', 'The Divine Mother: the most intimate face of God →', 'The simplest and most heartfelt invocation of the Divine Mother. Maa — "mother" — is the most intimate name for the goddess.', 'lotus'),
  (114, 'ॐ गं गणपतये नमः', 'Om Gam Ganapataye Namah', 'Om, with the seed of Ganesha, I bow to the lord of all beginnings.', 'vedic_ganesha', 'New Beginnings', 'OHM gahm gah-nah-PAH-tah-yay nah-MAH', 'om_gam_ganapataye_na.mp3', 'https://paulwagner.com', 'Why Ganesha is invoked first in every ritual →', 'Gam is Ganesha\'s bija mantra. Ganapati — "lord of the ganas" — is invoked at the beginning of every undertaking to remove obstacles.', 'seed_of_life'),
  (115, 'ॐ नमो गणेशाय', 'Om Namo Ganeshaya', 'Om, I bow to Ganesha — the lord of hosts.', 'vedic_ganesha', 'Beginnings', 'OHM nah-MOH gah-NAY-shah-yah', 'om_namo_ganeshaya.mp3', 'https://paulwagner.com', 'Ganesha\'s elephant head: the wisdom of the big picture →', 'Ganesha — "lord of the ganas" — is the remover of obstacles and the bestower of wisdom. He is invoked before all sacred activities.', 'seed_of_life'),
  (116, 'ॐ विघ्नराजाय नमः', 'Om Vighnarajaya Namah', 'Om, I bow to the king of obstacles — who removes all impediments.', 'vedic_ganesha', 'Obstacle Removal', 'OHM vig-nah-RAH-jah-yah nah-MAH', 'om_vighnarajaya_nama.mp3', 'https://paulwagner.com', 'Why Ganesha creates obstacles before removing them →', 'Vighnaraja — "king of obstacles" — is Ganesha\'s paradoxical title. He both creates and removes obstacles, teaching that challenges are divine gifts.', 'seed_of_life'),
  (117, 'ॐ एकदन्ताय नमः', 'Om Ekadantaya Namah', 'Om, I bow to the single-tusked one — the one who focuses on the essential.', 'vedic_ganesha', 'Focus', 'OHM ay-kah-DAHN-tah-yah nah-MAH', 'om_ekadantaya_namah.mp3', 'https://paulwagner.com', 'Why Ganesha broke his tusk to write the Mahabharata →', 'Ekadanta — "single tusk" — refers to Ganesha breaking off one tusk to write the Mahabharata. He teaches us to sacrifice the non-essential for the essential.', 'seed_of_life'),
  (118, 'ॐ लम्बोदराय नमः', 'Om Lambodaraya Namah', 'Om, I bow to the large-bellied one who contains all universes.', 'vedic_ganesha', 'Abundance', 'OHM lahm-boh-DAH-rah-yah nah-MAH', 'om_lambodaraya_namah.mp3', 'https://paulwagner.com', 'Ganesha\'s belly: the universe within →', 'Lambodara — "large belly" — represents Ganesha\'s capacity to contain all of existence. His belly holds the entire cosmos.', 'seed_of_life'),
  (119, 'ॐ विनायकाय नमः', 'Om Vinayakaya Namah', 'Om, I bow to Vinayaka — the supreme leader who guides without being led.', 'vedic_ganesha', 'Leadership', 'OHM vih-nah-YAH-kah-yah nah-MAH', 'om_vinayakaya_namah.mp3', 'https://paulwagner.com', 'True leadership: the Vinayaka principle →', 'Vinayaka — "supreme leader" or "one who has no master" — is Ganesha\'s most common name in South India.', 'seed_of_life'),
  (120, 'ॐ गजाननाय नमः', 'Om Gajananaya Namah', 'Om, I bow to the elephant-faced one.', 'vedic_ganesha', 'Wisdom', 'OHM gah-jah-NAH-nah-yah nah-MAH', 'om_gajananaya_namah.mp3', 'https://paulwagner.com', 'The elephant\'s wisdom: what Ganesha\'s head teaches →', 'Gajanana — "elephant-faced" — honors Ganesha\'s elephant head, which represents wisdom, memory, and the ability to remove obstacles with gentle power.', 'seed_of_life'),
  (121, 'ॐ गणाधिपाय नमः', 'Om Ganadhipaya Namah', 'Om, I bow to the lord of all groups and communities.', 'vedic_ganesha', 'Community', 'OHM gah-nah-dhih-PAH-yah nah-MAH', 'om_ganadhipaya_namah.mp3', 'https://paulwagner.com', 'Sangha: the power of spiritual community →', 'Ganadhipa — "lord of groups" — honors Ganesha as the presiding deity of all communities, councils, and collective endeavors.', 'seed_of_life'),
  (122, 'ॐ सिद्धिविनायकाय नमः', 'Om Siddhivinayakaya Namah', 'Om, I bow to Siddhivinayaka — the bestower of all accomplishments.', 'vedic_ganesha', 'Achievement', 'OHM sid-dhih-vih-nah-YAH-kah-yah nah-MAH', 'om_siddhivinayakaya.mp3', 'https://paulwagner.com', 'The eight siddhis: spiritual powers and how to use them →', 'Siddhivinayaka — "bestower of siddhi" — is the most popular form of Ganesha in Mumbai. Siddhi means accomplishment, perfection, and supernatural power.', 'seed_of_life'),
  (123, 'ॐ बुद्धिप्रियाय नमः', 'Om Buddhipriyaya Namah', 'Om, I bow to the one who loves intelligence.', 'vedic_ganesha', 'Intelligence', 'OHM bood-dhih-PRIH-yah-yah nah-MAH', 'om_buddhipriyaya_nam.mp3', 'https://paulwagner.com', 'Ganesha as the patron of learning: the student\'s mantra →', 'Buddhipriya — "lover of intelligence" — honors Ganesha as the patron of learning, scholarship, and all forms of intellectual endeavor.', 'seed_of_life'),
  (124, 'ॐ विद्याधिपाय नमः', 'Om Vidyadhipaya Namah', 'Om, I bow to the lord of all knowledge.', 'vedic_ganesha', 'Knowledge', 'OHM vid-yah-dhih-PAH-yah nah-MAH', 'om_vidyadhipaya_nama.mp3', 'https://paulwagner.com', 'Para vidya and apara vidya: two kinds of knowledge →', 'Vidyadhipa — "lord of knowledge" — honors Ganesha as the supreme patron of all forms of learning, from the sacred to the mundane.', 'seed_of_life'),
  (125, 'ॐ मूषकवाहनाय नमः', 'Om Mushakavahanaya Namah', 'Om, I bow to the one whose vehicle is the mouse.', 'vedic_ganesha', 'Humility', 'OHM moo-shah-kah-VAH-hah-nah-yah nah-MAH', 'om_mushakavahanaya_n.mp3', 'https://paulwagner.com', 'Why Ganesha rides a mouse: the paradox of power →', 'Ganesha rides a mouse — the smallest of vehicles for the largest of gods. The mouse represents the ego: small, quick, and capable of gnawing through obstacles.', 'seed_of_life'),
  (126, 'ॐ मोदकप्रियाय नमः', 'Om Modakapriyaya Namah', 'Om, I bow to the one who loves modaka — the sweet of bliss.', 'vedic_ganesha', 'Sweetness', 'OHM moh-dah-kah-PRIH-yah-yah nah-MAH', 'om_modakapriyaya_nam.mp3', 'https://paulwagner.com', 'Offering to Ganesha: the art of sacred giving →', 'Modaka — a sweet rice dumpling — is Ganesha\'s favorite offering. It represents the sweetness of spiritual realization.', 'seed_of_life'),
  (127, 'ॐ हेरम्बाय नमः', 'Om Herambaya Namah', 'Om, I bow to Heramba — the protector of the weak.', 'vedic_ganesha', 'Protection', 'OHM hay-RAHM-bah-yah nah-MAH', 'om_herambaya_namah.mp3', 'https://paulwagner.com', 'Heramba: Ganesha\'s fierce protective form →', 'Heramba — "protector of the weak" — is a five-headed form of Ganesha who specifically protects those who are vulnerable or in difficulty.', 'seed_of_life'),
  (128, 'ॐ महागणपतये नमः', 'Om Mahaganapataye Namah', 'Om, I bow to the great lord of all hosts.', 'vedic_ganesha', 'Greatness', 'OHM mah-hah-gah-nah-PAH-tah-yay nah-MAH', 'om_mahaganapataye_na.mp3', 'https://paulwagner.com', 'The 32 forms of Ganesha: a complete guide →', 'Mahaganapataye — "great Ganapati" — is the supreme form of Ganesha, combining all his powers and aspects into one.', 'seed_of_life'),
  (129, 'ॐ सरस्वत्यै नमः', 'Om Saraswatyai Namah', 'Om, I bow to Saraswati — goddess of wisdom, music, and learning.', 'vedic_shakti', 'Wisdom', 'OHM sah-rahs-WAH-tyay nah-MAH', 'mantra-129.mp3', 'https://paulwagner.com', 'Saraswati: the goddess who flows like a river →', 'Saraswati — "the flowing one" — is the goddess of knowledge, music, art, and speech. She flows like a river through the mind, bringing clarity and creative inspiration.', 'lotus'),
  (130, 'ॐ शारदायै नमः', 'Om Sharadayai Namah', 'Om, I bow to Sharada — Saraswati as the goddess of autumn and learning.', 'vedic_shakti', 'Clarity', 'OHM SHAH-rah-dah-yay nah-MAH', 'mantra-130.mp3', 'https://paulwagner.com', 'Sharada: the autumn goddess of clear knowledge →', 'Sharada — "the autumnal one" — is Saraswati as worshipped in Kashmir. Autumn is the season of clarity, when the sky is clearest and knowledge shines brightest.', 'lotus'),
  (131, 'ॐ वाग्देव्यै नमः', 'Om Vagdevyai Namah', 'Om, I bow to the goddess of speech.', 'vedic_shakti', 'Expression', 'OHM vahg-DAY-vyay nah-MAH', 'mantra-131.mp3', 'https://paulwagner.com', 'Sacred speech: how words shape reality →', 'Vagdevi — "goddess of speech" — is Saraswati as the power behind all language. Every word spoken with awareness becomes a creative act.', 'flower_of_life'),
  (132, 'ॐ वीणापुस्तकधारिण्यै नमः', 'Om Vinapustakadharinyai Namah', 'Om, I bow to the one who holds the veena and the book.', 'vedic_shakti', 'Art', 'OHM vee-nah-poos-tah-kah-DHAH-rin-yay nah-MAH', 'mantra-132.mp3', 'https://paulwagner.com', 'The veena and the book: art and knowledge united →', 'Saraswati holds a veena (stringed instrument) and a book — the union of art and knowledge. True wisdom is both intellectual and creative.', 'lotus'),
  (133, 'ॐ हंसवाहिन्यै नमः', 'Om Hamsavaहinyai Namah', 'Om, I bow to the one whose vehicle is the swan.', 'vedic_shakti', 'Discernment', 'OHM hahm-sah-VAH-hin-yay nah-MAH', 'mantra-133.mp3', 'https://paulwagner.com', 'The swan: the symbol of spiritual discernment →', 'Saraswati rides a swan — the hamsa — which in legend can separate milk from water. This represents viveka, the power of discernment between the real and the unreal.', 'seed_of_life'),
  (134, 'ॐ रामाय नमः', 'Om Ramaya Namah', 'Om, I bow to Rama — the embodiment of dharma.', 'vedic_vishnu', 'Righteousness', 'OHM RAH-mah-yah nah-MAH', 'mantra-134.mp3', 'https://paulwagner.com', 'Rama: the ideal of dharmic living →', 'Rama — the seventh avatar of Vishnu — embodies dharma in human form. His name means "one who delights" and is considered one of the most powerful mantras in existence.', 'flower_of_life'),
  (135, 'ॐ सीतारामाय नमः', 'Om Sitaramaya Namah', 'Om, I bow to Sita and Rama — the divine couple.', 'vedic_vishnu', 'Sacred Union', 'OHM see-tah-RAH-mah-yah nah-MAH', 'mantra-135.mp3', 'https://paulwagner.com', 'Sita and Rama: devotion beyond separation →', 'Sita and Rama together represent the perfect union of shakti and consciousness, devotion and dharma. Their love story is the heart of the Ramayana.', 'lotus'),
  (136, 'ॐ गं ॐ गं ॐ गं', 'Om Gam Om Gam Om Gam', 'Om, Ganesha\'s seed — three times — opening all doors.', 'vedic_ganesha', 'Opening', 'OHM gahm OHM gahm OHM gahm', 'om_gam_om_gam_om_gam.mp3', 'https://paulwagner.com', 'The root chakra and Ganesha: the foundation of practice →', 'The simplest Ganesha practice: just his bija, three times. Gam activates the root chakra and opens the path ahead.', 'seed_of_life'),
  (137, '', 'I am the I behind the Me', 'I am the I behind the Me', 'universal', 'Self-Realization', '', '', 'https://paulwagner.com', 'Why recognizing your inner light changes everything →', 'A powerful affirmation rooted in Vedantic truth — you are not the body, not the mind, but the luminous awareness that witnesses all.', 'sri_yantra'),
  (138, 'ॐ दशरथनन्दनाय नमः', 'Om Dasharathanandanaya Namah', 'Om, I bow to the beloved son of Dasharatha.', 'vedic_vishnu', 'Devotion', 'OHM dah-shah-rah-thah-NAHN-dah-nah-yah nah-MAH', 'mantra-138.mp3', 'https://paulwagner.com', 'The Ramayana: the world\'s first epic poem →', 'Dasharathanandana — "joy of Dasharatha" — honors Rama as the beloved son. Even God incarnate honored his father and family. Devotion begins at home.', 'flower_of_life'),
  (139, 'ॐ रघुनाथाय नमः', 'Om Raghunathaya Namah', 'Om, I bow to the lord of the Raghu dynasty.', 'vedic_vishnu', 'Leadership', 'OHM rah-ghoo-NAH-thah-yah nah-MAH', 'mantra-139.mp3', 'https://paulwagner.com', 'The Raghu dynasty: a lineage of dharmic kings →', 'Raghunatha — "lord of the Raghu clan" — honors Rama as the ideal leader who rules with dharma, compassion, and selfless service.', 'seed_of_life'),
  (140, 'ॐ रामचन्द्राय नमः', 'Om Ramachandraya Namah', 'Om, I bow to Ramachandra — Rama who is gentle as the moon.', 'vedic_vishnu', 'Gentleness', 'OHM rah-mah-CHAHN-drah-yah nah-MAH', 'mantra-140.mp3', 'https://paulwagner.com', 'The moon-like qualities of Rama →', 'Ramachandra — "Rama who is like the moon" — the moon is cool, gentle, and illuminates without burning. Rama\'s strength was always tempered with tenderness.', 'lotus'),
  (141, '', 'Who am I without this mask?', 'Who am I without this mask?', 'universal', 'Self-Love', '', '', 'https://paulwagner.com', 'The spiritual truth about self-worth →', 'Love is not something you earn — it is your birthright. This affirmation dissolves the false belief that you must perform to be loved.', 'sri_yantra'),
  (142, 'ॐ सूर्याय नमः', 'Om Suryaya Namah', 'Om, I bow to Surya — the solar deity, the source of all light.', 'vedic_solar', 'Vitality', 'OHM SOOR-yah-yah nah-MAH', 'om_suryaya_namah.mp3', 'https://paulwagner.com', 'Surya Namaskar: the sun salutation as prayer →', 'Surya is the solar deity — the visible form of the divine. The sun is the source of all life on earth and a symbol of the inner light of consciousness.', 'flower_of_life'),
  (143, 'ॐ आदित्याय नमः', 'Om Adityaya Namah', 'Om, I bow to Aditya — the son of Aditi, the infinite.', 'vedic_solar', 'Infinity', 'OHM ah-DIT-yah-yah nah-MAH', 'om_adityaya_namah.mp3', 'https://paulwagner.com', 'Aditi: the infinite mother of the gods →', 'Aditya — "son of Aditi" — is the sun as the child of the infinite. Aditi means "the boundless" — the cosmic mother of all the gods.', 'flower_of_life'),
  (144, 'ॐ मित्राय नमः', 'Om Mitraya Namah', 'Om, I bow to Mitra — the sun as the universal friend.', 'vedic_solar', 'Friendship', 'OHM MEET-rah-yah nah-MAH', 'om_mitraya_namah.mp3', 'https://paulwagner.com', 'Mitra: the sun as the friend of all beings →', 'Mitra — "friend" — is the sun as the universal benefactor. The sun shines equally on all without discrimination.', 'flower_of_life'),
  (145, 'ॐ रवये नमः', 'Om Ravaye Namah', 'Om, I bow to Ravi — the radiant one.', 'vedic_solar', 'Radiance', 'OHM RAH-vah-yay nah-MAH', 'om_ravaye_namah.mp3', 'https://paulwagner.com', 'The 12 names of the sun: the Surya Namaskar mantras →', 'Ravi — "the radiant" — is one of the twelve names of the sun recited during Surya Namaskar. Radiance is the sun\'s essential nature.', 'flower_of_life'),
  (146, 'ॐ सूर्याय नमः भास्कराय नमः', 'Om Suryaya Namah Bhaskaraya Namah', 'Om, I bow to Surya, I bow to Bhaskara — the one who illuminates.', 'vedic_solar', 'Clarity', 'OHM SOOR-yah-yah nah-MAH BHAHS-kah-rah-yah nah-MAH', 'om_suryaya_namah_bha.mp3', 'https://paulwagner.com', 'Light as a metaphor for consciousness →', 'Bhaskara — "the illuminator" — is the sun as the force that makes all things visible and knowable.', 'flower_of_life'),
  (147, 'ॐ खगाय नमः', 'Om Khagaya Namah', 'Om, I bow to Khaga — the one who moves through the sky.', 'vedic_solar', 'Freedom', 'OHM khah-GAH-yah nah-MAH', 'om_khagaya_namah.mp3', 'https://paulwagner.com', 'The sun\'s daily journey: a meditation on freedom →', 'Khaga — "sky-mover" — honors the sun\'s daily journey across the heavens. The sun\'s freedom of movement is a symbol of liberated consciousness.', 'flower_of_life'),
  (148, 'ॐ पूष्णे नमः', 'Om Pushne Namah', 'Om, I bow to Pushan — the nourisher of all.', 'vedic_solar', 'Nourishment', 'OHM POOSH-nay nah-MAH', 'om_pushne_namah.mp3', 'https://paulwagner.com', 'Pushan: the sun as the cosmic nourisher →', 'Pushan — "the nourisher" — is the sun as the source of all food and sustenance. The sun nourishes every living being without exception.', 'flower_of_life'),
  (149, 'ॐ हिरण्यगर्भाय नमः', 'Om Hiranyagarbhaya Namah', 'Om, I bow to Hiranyagarbha — the golden womb of creation.', 'vedic_solar', 'Creation', 'OHM hih-rahn-yah-GAHR-bhah-yah nah-MAH', 'om_hiranyagarbhaya_n.mp3', 'https://paulwagner.com', 'Hiranyagarbha: the golden egg of creation →', 'Hiranyagarbha — "golden womb" — is the cosmic egg from which the universe was born. The sun is its visible manifestation.', 'flower_of_life'),
  (150, 'ॐ मरीचये नमः', 'Om Marichaye Namah', 'Om, I bow to Marichi — the ray of light.', 'vedic_solar', 'Subtlety', 'OHM mah-REE-chah-yay nah-MAH', 'om_marichaye_namah.mp3', 'https://paulwagner.com', 'The ray and the sun: the relationship between soul and God →', 'Marichi — "ray of light" — honors the individual rays of the sun. Each ray is both part of the sun and distinct from it — like each soul in relation to the divine.', 'flower_of_life'),
  (151, 'ॐ आदित्याय सवित्रे नमः', 'Om Adityaya Savitre Namah', 'Om, I bow to Aditya-Savitri — the solar deity who animates all life.', 'vedic_solar', 'Animation', 'OHM ah-DIT-yah-yah sah-VIT-ray nah-MAH', 'om_adityaya_savitre.mp3', 'https://paulwagner.com', 'Prana: the solar life force within you →', 'Savitri — "the animating one" — is the sun as the force that animates all living beings. Without the sun, there is no life.', 'flower_of_life'),
  (152, 'ॐ दिवाकराय नमः', 'Om Divakaraya Namah', 'Om, I bow to Divakara — the maker of the day.', 'vedic_solar', 'New Day', 'OHM dee-vah-KAH-rah-yah nah-MAH', 'om_divakaraya_namah.mp3', 'https://paulwagner.com', 'The gift of each new day: a morning practice →', 'Divakara — "day-maker" — honors the sun as the creator of each new day. Every sunrise is a new beginning, a fresh opportunity.', 'flower_of_life'),
  (153, 'ॐ प्रभाकराय नमः', 'Om Prabhakaraya Namah', 'Om, I bow to Prabhakara — the maker of light.', 'vedic_solar', 'Enlightenment', 'OHM prah-bhah-KAH-rah-yah nah-MAH', 'om_prabhakaraya_nama.mp3', 'https://paulwagner.com', 'Enlightenment: what it really means →', 'Prabhakara — "maker of light" — honors the sun as the source of all illumination, both physical and spiritual.', 'flower_of_life'),
  (154, 'ॐ विवस्वते नमः', 'Om Vivasvate Namah', 'Om, I bow to Vivasvat — the brilliant, shining one.', 'vedic_solar', 'Brilliance', 'OHM vih-VAHS-vah-tay nah-MAH', 'om_vivasvate_namah.mp3', 'https://paulwagner.com', 'The eternal yoga: Krishna\'s teaching to the sun →', 'Vivasvat — "the brilliant" — is the Vedic name of the sun. In the Bhagavad Gita, Krishna says he first taught this yoga to Vivasvat.', 'flower_of_life'),
  (155, 'ॐ सवित्रे नमः', 'Om Savitre Namah', 'Om, I bow to Savitri — the solar deity of the Gayatri.', 'vedic_solar', 'Inspiration', 'OHM sah-VIT-ray nah-MAH', 'om_savitre_namah.mp3', 'https://paulwagner.com', 'Savitri: the goddess behind the Gayatri Mantra →', 'Savitri is the specific solar deity invoked in the Gayatri Mantra. The name means "one who inspires" or "one who animates."', 'sri_yantra'),
  (156, 'ॐ आर्काय नमः', 'Om Arkaya Namah', 'Om, I bow to Arka — the sun as the worthy of praise.', 'vedic_solar', 'Gratitude', 'OHM AHR-kah-yah nah-MAH', 'om_arkaya_namah.mp3', 'https://paulwagner.com', 'Gratitude as a spiritual practice →', 'Arka — "worthy of praise" — honors the sun as the most visible and constant blessing in our lives. Gratitude for the sun is gratitude for life itself.', 'flower_of_life'),
  (157, 'ॐ भानवे नमः', 'Om Bhanave Namah', 'Om, I bow to Bhanu — the luminous one.', 'vedic_solar', 'Luminosity', 'OHM BHAH-nah-vay nah-MAH', 'om_bhanave_namah.mp3', 'https://paulwagner.com', 'Your natural luminosity: the practice of shining →', 'Bhanu — "luminous" — is one of the twelve names of the sun. Luminosity is the sun\'s nature; it cannot help but shine.', 'flower_of_life'),
  (158, 'ॐ इन्द्राय नमः', 'Om Indraya Namah', 'Om, I bow to Indra — the king of the gods, lord of lightning.', 'vedic_solar', 'Power', 'OHM IN-drah-yah nah-MAH', 'om_indraya_namah.mp3', 'https://paulwagner.com', 'Indra and the thunderbolt: the power of awakening →', 'Indra is the king of the Vedic gods, wielder of the thunderbolt (vajra). He represents the power of the awakened mind.', 'flower_of_life'),
  (159, 'ॐ वरुणाय नमः', 'Om Varunaya Namah', 'Om, I bow to Varuna — the lord of cosmic order and the waters.', 'vedic_solar', 'Order', 'OHM vah-ROO-nah-yah nah-MAH', 'om_varunaya_namah.mp3', 'https://paulwagner.com', 'Rita: the cosmic order that underlies all existence →', 'Varuna is the Vedic god of cosmic order (rita) and the waters. He sees all actions and maintains the moral order of the universe.', 'flower_of_life'),
  (160, 'ॐ अग्नये नमः', 'Om Agnaye Namah', 'Om, I bow to Agni — the sacred fire, the divine messenger.', 'vedic_solar', 'Purification', 'OHM AHG-nah-yay nah-MAH', 'om_agnaye_namah.mp3', 'https://paulwagner.com', 'Agni: the first word of the Vedas →', 'Agni is the first word of the Rigveda. The sacred fire is the divine messenger between humans and gods, and the purifier of all offerings.', 'flower_of_life'),
  (161, 'ॐ वायवे नमः', 'Om Vayave Namah', 'Om, I bow to Vayu — the wind, the breath of life.', 'vedic_solar', 'Breath', 'OHM VAH-yah-vay nah-MAH', 'om_vayave_namah.mp3', 'https://paulwagner.com', 'Pranayama: the yoga of the breath →', 'Vayu — "wind" or "breath" — is the Vedic god of air and prana. The breath is the most direct link between the physical and spiritual.', 'flower_of_life'),
  (162, 'ॐ पृथिव्यै नमः', 'Om Prithivyai Namah', 'Om, I bow to Prithivi — the earth, our mother.', 'vedic_solar', 'Grounding', 'OHM prih-THIV-yay nah-MAH', 'om_prithivyai_namah.mp3', 'https://paulwagner.com', 'Prithivi: the earth as the divine mother →', 'Prithivi — "the broad one" — is the Vedic earth goddess. The earth supports all life without discrimination. Grounding is the foundation of all practice.', 'lotus'),
  (163, 'ॐ आपः शान्तिः', 'Om Apah Shantih', 'Om, may the waters bring peace.', 'vedic_solar', 'Peace', 'OHM AH-pah SHAHN-tih', 'om_apah_shantih.mp3', 'https://paulwagner.com', 'The Shanti Patha: the Vedic prayer for universal peace →', 'From the Shanti Patha — the Vedic peace invocation. The waters (apah) represent the flow of life and the cleansing power of grace.', 'lotus'),
  (164, 'ॐ ओषधयः शान्तिः', 'Om Oshadhayah Shantih', 'Om, may the herbs and plants bring peace.', 'vedic_solar', 'Healing', 'OHM oh-shah-DHAH-yah SHAHN-tih', 'om_oshadhayah_shanti.mp3', 'https://paulwagner.com', 'Ayurveda: the Vedic science of healing →', 'From the Shanti Patha. The healing plants of the earth are invoked for peace — honoring the medicinal wisdom of the natural world.', 'lotus'),
  (165, 'ॐ विश्वानि देव सवितर्', 'Om Vishwani Deva Savitar', 'O divine Savitri, remove all that is harmful from us.', 'vedic_solar', 'Purification', 'OHM vish-WAH-nih DAY-vah sah-VEE-tahr', 'om_vishwani_deva_sav.mp3', 'https://paulwagner.com', 'The Yajurveda: the Veda of ritual action →', 'From the Yajurveda. A prayer to the solar deity to remove all that is harmful and bring only what is beneficial.', 'sri_yantra'),
  (166, 'ॐ शरवणभवाय नमः', 'Om Sharavanabhavaya Namah', 'Om, I bow to the one born in the forest of reeds.', 'vedic_shiva', 'Divine Birth', 'OHM shah-rah-vah-nah-BHAH-vah-yah nah-MAH', 'mantra-166.mp3', 'https://paulwagner.com', 'Skanda: the warrior son of Shiva →', 'Sharavanabhava — "born in the reed forest" — is Skanda/Murugan, the six-faced son of Shiva. Born to defeat the demon Tarakasura, he represents the focused power of divine will.', 'sri_yantra'),
  (167, 'ॐ मुरुगाय नमः', 'Om Murugaya Namah', 'Om, I bow to Muruga — the beautiful, divine youth.', 'vedic_shiva', 'Youthfulness', 'OHM moo-ROO-gah-yah nah-MAH', 'mantra-167.mp3', 'https://paulwagner.com', 'Murugan: the eternally young warrior god →', 'Muruga — "the beautiful one" — is the Tamil name for Skanda. He is the eternally youthful warrior who wields the vel (spear) of wisdom.', 'flower_of_life'),
  (168, 'ॐ सूर्य नमस्कार', 'Om Surya Namaskar', 'Om, salutation to the sun.', 'vedic_solar', 'Gratitude', 'OHM SOOR-yah nah-mahs-KAHR', 'om_surya_namaskar.mp3', 'https://paulwagner.com', 'The complete Surya Namaskar practice →', 'Surya Namaskar — "sun salutation" — is both a physical yoga practice and a devotional act. Each movement is accompanied by a mantra to the sun.', 'flower_of_life'),
  (169, 'ॐ ह्रां ह्रीं ह्रौं सः सूर्याय नमः', 'Om Hram Hrim Hraum Sah Suryaya Namah', 'Om — the three solar bija mantras — I am that — I bow to Surya.', 'vedic_solar', 'Solar Power', 'OHM hrahm hreem hrowm sah SOOR-yah-yah nah-MAH', 'om_hram_hrim_hraum_s.mp3', 'https://paulwagner.com', 'Solar bija mantras: seeds of solar power →', 'The complete solar bija mantra. Hram, Hrim, Hraum are the three seed syllables of the sun, representing its three aspects: rising, noon, and setting.', 'sri_yantra'),
  (170, 'ॐ सुब्रह्मण्याय नमः', 'Om Subrahmanyaya Namah', 'Om, I bow to Subrahmanya — the auspicious one dear to Brahmins.', 'vedic_shiva', 'Sacred Knowledge', 'OHM soob-rah-MAHN-yah-yah nah-MAH', 'mantra-170.mp3', 'https://paulwagner.com', 'Subrahmanya: the teacher of the Pranava →', 'Subrahmanya — another name for Skanda — is the deity who taught the meaning of Om even to his father Shiva. He represents the highest spiritual knowledge.', 'sri_yantra'),
  (171, 'ॐ कार्तिकेयाय नमः', 'Om Kartikeyaya Namah', 'Om, I bow to Kartikeya — the commander of the divine army.', 'vedic_shiva', 'Discipline', 'OHM kahr-tih-KAY-yah-yah nah-MAH', 'mantra-171.mp3', 'https://paulwagner.com', 'Kartikeya: the six-faced god of war and wisdom →', 'Kartikeya — "son of the Krittikas (Pleiades)" — is the commander of the gods\' army. He represents disciplined focus and the courage to face inner demons.', 'seed_of_life'),
  (172, 'ॐ भैषज्यगुरु वैडूर्यप्रभाय नमः', 'Om Bhaishajyaguru Vaiduryaprabha Namah', 'Om, I bow to the Medicine Buddha — the lapis lazuli radiance.', 'buddhist', 'Healing', 'OHM BHY-shah-jyah-GOO-roo vy-DOOR-yah-PRAH-bhah nah-MAH', 'mantra-172.mp3', 'https://paulwagner.com', 'The Medicine Buddha: healing body, speech, and mind →', 'The Medicine Buddha — Bhaishajyaguru — radiates lapis lazuli light that heals all illness of body, speech, and mind. His practice is one of the most beloved in Mahayana Buddhism.', 'lotus'),
  (173, 'ॐ अमिताभाय नमः', 'Om Amitabhaya Namah', 'Om, I bow to Amitabha — the Buddha of infinite light.', 'buddhist', 'Infinite Light', 'OHM ah-mih-TAH-bhah-yah nah-MAH', 'mantra-173.mp3', 'https://paulwagner.com', 'Amitabha: the Buddha of the Western Pure Land →', 'Amitabha — "infinite light" — is the Buddha of the Western Pure Land. His light reaches all beings without exception. This mantra invokes his boundless compassion.', 'flower_of_life'),
  (174, 'ॐ नमः सूर्याय शान्ताय', 'Om Namah Suryaya Shantaya', 'Om, I bow to the peaceful sun.', 'vedic_solar', 'Equanimity', 'OHM nah-MAH SOOR-yah-yah SHAHN-tah-yah', 'om_namah_suryaya_sha.mp3', 'https://paulwagner.com', 'Equanimity: the sun\'s greatest teaching →', 'The sun is peaceful — it shines without effort, without preference, without agitation. This mantra invokes solar equanimity.', 'flower_of_life'),
  (175, 'ॐ नमः सूर्याय सर्वदाय', 'Om Namah Suryaya Sarvadaya', 'Om, I bow to the sun who gives everything.', 'vedic_solar', 'Generosity', 'OHM nah-MAH SOOR-yah-yah sahr-VAH-dah-yah', 'om_namah_suryaya_sar.mp3', 'https://paulwagner.com', 'The sun\'s generosity: giving without expectation →', 'The sun gives its light freely to all — the saint and the sinner, the rich and the poor. This mantra invokes divine generosity.', 'flower_of_life'),
  (176, 'ॐ सूर्य देव नमोऽस्तु ते', 'Om Surya Deva Namostu Te', 'Om, I bow to you, O solar deity.', 'vedic_solar', 'Reverence', 'OHM SOOR-yah DAY-vah nah-MOHS-too tay', 'om_surya_deva_namost.mp3', 'https://paulwagner.com', 'Daily sun practice: the simplest solar sadhana →', 'A simple, direct salutation to the sun. Namostu — "may there be bowing" — expresses perpetual reverence.', 'flower_of_life'),
  (177, 'ॐ प्रसीद प्रसीद प्रभो', 'Om Prasida Prasida Prabho', 'Om, be pleased, be pleased, O Lord.', 'vedic_solar', 'Grace', 'OHM prah-SEE-dah prah-SEE-dah PRAH-bhoh', 'om_prasida_prasida_p.mp3', 'https://paulwagner.com', 'Prasada: the grace that flows from the divine →', 'Prasida — "be pleased" or "be gracious" — is a prayer for divine grace. The triple repetition intensifies the request.', 'flower_of_life'),
  (178, 'ॐ सर्वदेवनमस्कारः', 'Om Sarvadevanamaskarah', 'Om, salutation to all the gods.', 'vedic_solar', 'Inclusivity', 'OHM sahr-vah-DAY-vah-nah-mahs-KAH-rah', 'om_sarvadevanamaskar.mp3', 'https://paulwagner.com', 'Ekam sat vipra bahudha vadanti: one truth, many names →', 'A universal salutation to all divine forms. The Vedas teach that all gods are aspects of the one divine reality.', 'flower_of_life'),
  (179, 'ॐ अमितायुस् नमः', 'Om Amitayus Namah', 'Om, I bow to Amitayus — the Buddha of infinite life.', 'buddhist', 'Longevity', 'OHM ah-mih-TAH-yoos nah-MAH', 'mantra-179.mp3', 'https://paulwagner.com', 'Amitayus: the long-life Buddha practice →', 'Amitayus — "infinite life" — is Amitabha in his longevity aspect. This mantra is chanted for long life, not of the body alone, but of awareness itself.', 'lotus'),
  (180, 'ॐ तेजोऽसि तेजो मयि धेहि', 'Om Tejo\'si Tejo Mayi Dhehi', 'Om, you are radiance — place that radiance in me.', 'vedic_solar', 'Empowerment', 'OHM tay-JOH-see tay-JOH mah-YEE DHAY-hee', 'om_tejosi_tejo_mayi.mp3', 'https://paulwagner.com', 'Tejas: the inner radiance of the awakened person →', 'From the Yajurveda. A prayer to receive the sun\'s radiance — not just its physical light, but its inner quality of brilliance and clarity.', 'sri_yantra'),
  (181, 'ॐ वीर्यमसि वीर्यं मयि धेहि', 'Om Viryamasi Viryam Mayi Dhehi', 'Om, you are vitality — place that vitality in me.', 'vedic_solar', 'Vitality', 'OHM veer-YAHM-ah-see veer-YAHM mah-YEE DHAY-hee', 'om_viryamasi_viryam.mp3', 'https://paulwagner.com', 'Virya: the heroic energy of the spiritual warrior →', 'From the Yajurveda. Virya — "vitality" or "heroic energy" — is the solar quality of dynamic, purposeful action.', 'flower_of_life'),
  (182, 'ॐ बलमसि बलं मयि धेहि', 'Om Balamasi Balam Mayi Dhehi', 'Om, you are strength — place that strength in me.', 'vedic_solar', 'Strength', 'OHM bah-LAHM-ah-see bah-LAHM mah-YEE DHAY-hee', 'om_balamasi_balam_ma.mp3', 'https://paulwagner.com', 'Bala: the strength that comes from practice →', 'From the Yajurveda. Bala — "strength" — is the solar quality of physical and spiritual fortitude. The sun never wavers; neither should we.', 'flower_of_life'),
  (183, 'ॐ मणि पद्मे हूँ', 'Om Mani Padme Hum', 'Om — the jewel in the lotus — hum.', 'buddhist', 'Compassion', 'OHM mah-NEE pahd-MAY hoom', 'om_mani_padme_hum.mp3', 'https://paulwagner.com', 'Om Mani Padme Hum: the six syllables of compassion →', 'The mantra of Avalokiteshvara — the bodhisattva of compassion. The most widely chanted mantra in the world. The jewel is the awakened mind; the lotus is the world.', 'lotus'),
  (184, 'ॐ तारे तुत्तारे तुरे स्वाहा', 'Om Tare Tuttare Ture Svaha', 'Om — Tara who liberates — Tara who liberates swiftly — Tara who protects — so be it.', 'buddhist', 'Liberation', 'OHM TAH-ray too-TAH-ray TOO-ray svah-HAH', 'om_tare_tuttare_ture.mp3', 'https://paulwagner.com', 'Green Tara: the swift liberator →', 'The mantra of Green Tara — the swift-acting bodhisattva who saves from the eight fears. Tare means "she who liberates."', 'lotus'),
  (185, 'ॐ अमिताभ हृदय', 'Om Amitabha Hridaya', 'Om — the heart of Amitabha — the buddha of infinite light.', 'buddhist', 'Light', 'OHM ah-mee-TAH-bhah hrih-DAH-yah', 'om_amitabha_hridaya.mp3', 'https://paulwagner.com', 'Amitabha Buddha: the pure land of infinite light →', 'Amitabha — "infinite light" — is the buddha of the western pure land. His light reaches all beings without exception.', 'lotus'),
  (186, 'नमो अमिताभाय', 'Namo Amitabhaya', 'I take refuge in Amitabha — the buddha of infinite light.', 'buddhist', 'Refuge', 'nah-MOH ah-mee-TAH-bhah-yah', 'namo_amitabhaya.mp3', 'https://paulwagner.com', 'The nembutsu: the simplest Buddhist practice →', 'The nembutsu — the central practice of Pure Land Buddhism. Reciting Amitabha\'s name with sincere faith is said to ensure rebirth in the pure land.', 'lotus'),
  (187, 'ॐ अह हूँ वज्र गुरु पद्म सिद्धि हूँ', 'Om Ah Hum Vajra Guru Padma Siddhi Hum', 'Om Ah Hum — Vajra Guru — lotus-born — accomplishment — Hum.', 'buddhist', 'Mastery', 'OHM ah hoom VAHJ-rah GOO-roo PAHD-mah SID-dhee hoom', 'om_ah_hum_vajra_guru.mp3', 'https://paulwagner.com', 'Padmasambhava: the lotus-born master of Tibet →', 'The mantra of Padmasambhava — Guru Rinpoche — who brought Buddhism to Tibet. The most important mantra in Vajrayana Buddhism.', 'lotus'),
  (188, 'ॐ बज्र सत्त्व हूँ', 'Om Vajrasattva Hum', 'Om — Vajrasattva — the diamond being — Hum.', 'buddhist', 'Purification', 'OHM VAHJ-rah-saht-tvah hoom', 'om_vajrasattva_hum.mp3', 'https://paulwagner.com', 'Vajrasattva: the 100-syllable purification practice →', 'The short mantra of Vajrasattva — the buddha of purification. Vajra means "diamond" or "thunderbolt" — indestructible and pure.', 'lotus'),
  (189, 'ॐ नमो मञ्जुश्रीये', 'Om Namo Manjushriye', 'Om, I bow to Manjushri — the bodhisattva of wisdom.', 'buddhist', 'Wisdom', 'OHM nah-MOH mahn-JOO-shree-yay', 'om_namo_manjushriye.mp3', 'https://paulwagner.com', 'Manjushri\'s sword: cutting through ignorance →', 'Manjushri holds a flaming sword to cut through ignorance and a book of wisdom. He is the embodiment of prajna — transcendent wisdom.', 'lotus'),
  (190, 'ॐ अ रा पा चा ना धीः', 'Om A Ra Pa Ca Na Dhih', 'Om — the five wisdom syllables — the seed of wisdom.', 'buddhist', 'Wisdom', 'OHM ah rah pah chah nah dhee', 'om_a_ra_pa_ca_na_dhi.mp3', 'https://paulwagner.com', 'The five wisdom syllables of Manjushri →', 'The mantra of Manjushri. Each syllable represents a wisdom teaching. Dhih is the seed syllable of wisdom — the most important syllable.', 'lotus'),
  (191, 'ॐ गते गते पारगते पारसंगते बोधि स्वाहा', 'Om Gate Gate Paragate Parasamgate Bodhi Svaha', 'Gone, gone, gone beyond, gone completely beyond — awakening — so be it.', 'buddhist', 'Transcendence', 'OHM GAH-tay GAH-tay pah-rah-GAH-tay pah-rah-sahm-GAH-tay BOH-dhee svah-HAH', 'om_gate_gate_paragat.mp3', 'https://paulwagner.com', 'The Heart Sutra: the Buddha\'s teaching on emptiness →', 'The dharani from the Heart Sutra — the most concise expression of the Buddha\'s teaching on emptiness and transcendence.', 'lotus'),
  (192, 'बुद्धं शरणं गच्छामि', 'Buddham Saranam Gacchami', 'I take refuge in the Buddha.', 'buddhist', 'Refuge', 'BOOD-dhahm shah-RAH-nahm GAHCH-chah-mee', 'buddham_saranam_gacc.mp3', 'https://paulwagner.com', 'The Three Jewels: the foundation of Buddhist practice →', 'The first of the Three Jewels — the triple refuge that is the foundation of all Buddhist practice. The Buddha is the awakened teacher.', 'lotus'),
  (193, 'धम्मं शरणं गच्छामि', 'Dhammam Saranam Gacchami', 'I take refuge in the Dharma — the teaching.', 'buddhist', 'Guidance', 'DHAHM-mahm shah-RAH-nahm GAHCH-chah-mee', 'dhammam_saranam_gacc.mp3', 'https://paulwagner.com', 'The Dharma: what the Buddha actually taught →', 'The second of the Three Jewels. Dharma is the Buddha\'s teaching — the path that leads to liberation from suffering.', 'lotus'),
  (194, 'संघं शरणं गच्छामि', 'Sangham Saranam Gacchami', 'I take refuge in the Sangha — the community.', 'buddhist', 'Community', 'SAHNG-ghahm shah-RAH-nahm GAHCH-chah-mee', 'sangham_saranam_gacc.mp3', 'https://paulwagner.com', 'Sangha: why community is essential for awakening →', 'The third of the Three Jewels. Sangha is the community of practitioners — those who walk the path together.', 'lotus'),
  (195, 'सर्वे सत्त्वाः सुखिनो भवन्तु', 'Sarve Sattvah Sukhino Bhavantu', 'May all beings be happy.', 'buddhist', 'Loving-Kindness', 'SAHR-vay saht-TVAH soo-KHIH-noh bhah-VAHN-too', 'sarve_sattvah_sukhin.mp3', 'https://paulwagner.com', 'Metta meditation: the practice of loving-kindness →', 'The metta (loving-kindness) prayer — the foundation of Buddhist compassion practice. It begins with all beings and works inward.', 'lotus'),
  (196, 'ॐ विकटाय नमः', 'Om Vikataya Namah', 'Om, I bow to Vikata — the unusual, extraordinary Ganesha.', 'vedic_ganesha', 'Uniqueness', 'OHM vih-KAH-tah-yah nah-MAH', 'mantra-196.mp3', 'https://paulwagner.com', 'Vikata: embracing what makes you different →', 'Vikata — "the unusual one" — is one of the twelve names of Ganesha. With an elephant head on a human body, Ganesha is the most unusual of all gods — and the most beloved. Uniqueness is divine.', 'seed_of_life'),
  (197, 'ॐ द्विमुखाय नमः', 'Om Dvimukhaya Namah', 'Om, I bow to the two-faced Ganesha who sees both worlds.', 'vedic_ganesha', 'Dual Vision', 'OHM dvee-MOO-khah-yah nah-MAH', 'mantra-197.mp3', 'https://paulwagner.com', 'The 32 forms of Ganesha: seeing in all directions →', 'Dvimukha — "two-faced" — is a form of Ganesha who simultaneously sees the material and spiritual worlds. This mantra develops the ability to live in both.', 'seed_of_life'),
  (198, 'ॐ स्वस्ति प्रजाभ्यः', 'Om Svasti Prajabhyah', 'Om, may all beings be well.', 'buddhist', 'Wellbeing', 'OHM SVAHS-tee prah-JAH-bhyah', 'om_svasti_prajabhyah.mp3', 'https://paulwagner.com', 'Svasti: the original meaning of the swastika →', 'A universal Buddhist blessing. Svasti — "well-being" — is the root of the Sanskrit word swastika, an ancient symbol of auspiciousness.', 'lotus'),
  (199, 'ॐ नमो बुद्धाय', 'Om Namo Buddhaya', 'Om, I bow to the Buddha — the awakened one.', 'buddhist', 'Awakening', 'OHM nah-MOH BOOD-dhah-yah', 'om_namo_buddhaya.mp3', 'https://paulwagner.com', 'What does it mean to be awakened? →', 'A simple, direct invocation of the Buddha. Buddha means "the awakened one" — one who has seen through the illusion of the separate self.', 'lotus'),
  (200, 'ॐ नमो धर्माय', 'Om Namo Dharmaya', 'Om, I bow to the Dharma — the truth.', 'buddhist', 'Truth', 'OHM nah-MOH DHAHR-mah-yah', 'om_namo_dharmaya.mp3', 'https://paulwagner.com', 'The Dharma: the Buddha\'s four noble truths →', 'Bowing to the Dharma is bowing to truth itself — the way things actually are, beyond our concepts and preferences.', 'lotus'),
  (201, 'ॐ नमो संघाय', 'Om Namo Sanghaya', 'Om, I bow to the Sangha — the community of practitioners.', 'buddhist', 'Community', 'OHM nah-MOH SAHNG-ghah-yah', 'om_namo_sanghaya.mp3', 'https://paulwagner.com', 'The bodhisattva vow: awakening for all beings →', 'The sangha is not just monks — it is all beings who walk the path of awakening. We are never alone on this journey.', 'lotus'),
  (202, 'ॐ अमोघपाश हूँ', 'Om Amoghapasha Hum', 'Om — the infallible lasso of compassion — Hum.', 'buddhist', 'Compassion', 'OHM ah-MOH-ghah-PAH-shah hoom', 'om_amoghapasha_hum.mp3', 'https://paulwagner.com', 'Avalokiteshvara: the bodhisattva who hears all cries →', 'Amoghapasha — "infallible lasso" — is a form of Avalokiteshvara who catches all beings in the net of compassion, leaving none behind.', 'lotus'),
  (203, 'ॐ नमो भगवते अमिताभाय', 'Om Namo Bhagavate Amitabhaya', 'Om, I bow to the blessed Amitabha.', 'buddhist', 'Light', 'OHM nah-MOH bhah-gah-VAH-tay ah-mee-TAH-bhah-yah', 'om_namo_bhagavate_am.mp3', 'https://paulwagner.com', 'The pure land: is it real or metaphorical? →', 'The full refuge mantra of Amitabha Buddha. Bhagavate — "blessed one" — is the honorific used for all buddhas.', 'lotus'),
  (204, 'ॐ मेत्ता मेत्ता मेत्ता', 'Om Metta Metta Metta', 'Om — loving-kindness, loving-kindness, loving-kindness.', 'buddhist', 'Loving-Kindness', 'OHM MET-tah MET-tah MET-tah', 'om_metta_metta_metta.mp3', 'https://paulwagner.com', 'The four brahmaviharas: the divine abodes →', 'Metta (Pali) or Maitri (Sanskrit) — loving-kindness — is the first of the four brahmaviharas, the divine abodes. Triple repetition deepens the intention.', 'lotus'),
  (205, 'ॐ करुणा करुणा करुणा', 'Om Karuna Karuna Karuna', 'Om — compassion, compassion, compassion.', 'buddhist', 'Compassion', 'OHM kah-ROO-nah kah-ROO-nah kah-ROO-nah', 'om_karuna_karuna_kar.mp3', 'https://paulwagner.com', 'Karuna: the difference between compassion and pity →', 'Karuna — compassion — is the second brahmavihara. It is the wish for all beings to be free from suffering.', 'lotus'),
  (206, 'ॐ मुदिता मुदिता मुदिता', 'Om Mudita Mudita Mudita', 'Om — sympathetic joy, sympathetic joy, sympathetic joy.', 'buddhist', 'Joy', 'OHM moo-DIH-tah moo-DIH-tah moo-DIH-tah', 'om_mudita_mudita_mud.mp3', 'https://paulwagner.com', 'Mudita: the antidote to envy →', 'Mudita — "sympathetic joy" — is the third brahmavihara: the ability to rejoice in the happiness of others without envy.', 'lotus'),
  (207, 'ॐ उपेक्षा उपेक्षा उपेक्षा', 'Om Upekkha Upekkha Upekkha', 'Om — equanimity, equanimity, equanimity.', 'buddhist', 'Equanimity', 'OHM oo-PEK-shah oo-PEK-shah oo-PEK-shah', 'om_upekkha_upekkha_u.mp3', 'https://paulwagner.com', 'Equanimity: the highest of the four divine abodes →', 'Upekkha — equanimity — is the fourth brahmavihara: the ability to remain balanced and undisturbed in all circumstances.', 'lotus'),
  (208, 'ॐ शान्ति शान्ति शान्ति', 'Om Shanti Shanti Shanti', 'Om — peace, peace, peace.', 'buddhist', 'Peace', 'OHM SHAHN-tee SHAHN-tee SHAHN-tee', 'om_shanti_shanti_sha.mp3', 'https://paulwagner.com', 'The three levels of peace: body, speech, and mind →', 'The universal peace invocation. Three repetitions address the three sources of disturbance: body, speech, and mind.', 'lotus'),
  (209, 'ॐ नमो रत्नत्रयाय', 'Om Namo Ratnatrayaya', 'Om, I bow to the three jewels.', 'buddhist', 'Refuge', 'OHM nah-MOH raht-nah-TRAH-yah-yah', 'om_namo_ratnatrayaya.mp3', 'https://paulwagner.com', 'Taking refuge: what it really means →', 'Ratnatraya — "three jewels" — are the Buddha, Dharma, and Sangha. Taking refuge in them is the foundation of all Buddhist practice.', 'lotus'),
  (210, 'ॐ नमो भगवते शाक्यमुनये', 'Om Namo Bhagavate Shakyamunaye', 'Om, I bow to the blessed Shakyamuni — the sage of the Shakya clan.', 'buddhist', 'Gratitude', 'OHM nah-MOH bhah-gah-VAH-tay SHAHK-yah-moo-nah-yay', 'om_namo_bhagavate_sh.mp3', 'https://paulwagner.com', 'The historical Buddha: his life and awakening →', 'Shakyamuni — "sage of the Shakyas" — is the historical Buddha, Siddhartha Gautama. This mantra honors the human teacher who showed the way.', 'lotus'),
  (211, 'ॐ अह हूँ', 'Om Ah Hum', 'Om — body, speech, mind — Hum.', 'buddhist', 'Integration', 'OHM ah hoom', 'om_ah_hum.mp3', 'https://paulwagner.com', 'Om Ah Hum: the three vajras of body, speech, and mind →', 'The three seed syllables of Vajrayana Buddhism: Om purifies the body, Ah purifies speech, Hum purifies the mind.', 'lotus'),
  (212, 'ॐ धूम्रवर्णाय नमः', 'Om Dhumravarnaya Namah', 'Om, I bow to the smoke-colored Ganesha who absorbs all negativity.', 'vedic_ganesha', 'Purification', 'OHM DHOOM-rah-VAHR-nah-yah nah-MAH', 'mantra-212.mp3', 'https://paulwagner.com', 'The smoke-colored Ganesha: absorbing darkness →', 'Dhumravarna — "smoke-colored" — is Ganesha in his form that absorbs and neutralizes negative energies. Like smoke rising from a sacred fire, he transforms impurity into offering.', 'sri_yantra'),
  (213, 'अनुपालय', 'Anupalaya', 'Please uphold me.', 'buddhist', 'Support', 'ah-noo-PAH-lah-yah', 'anupalaya.mp3', 'https://paulwagner.com', 'The 100-syllable Vajrasattva mantra: complete guide →', 'From the Vajrasattva mantra. A prayer for the divine to uphold and sustain the practitioner on the path.', 'lotus'),
  (214, 'ॐ नमो मञ्जुश्रीये नमः', 'Om Namo Manjushriye Namah', 'Om, I bow to Manjushri — the gentle-voiced one.', 'buddhist', 'Learning', 'OHM nah-MOH mahn-JOO-shree-yay nah-MAH', 'om_namo_manjushriye_d214.mp3', 'https://paulwagner.com', 'Manjushri: the bodhisattva of wisdom →', 'Manjushri — "gentle glory" — is the bodhisattva of wisdom. His name means "gentle-voiced" — wisdom is always gentle, never harsh.', 'lotus'),
  (215, 'ॐ वज्रपाणये नमः', 'Om Vajrapanaye Namah', 'Om, I bow to Vajrapani — the thunderbolt-wielder.', 'buddhist', 'Power', 'OHM VAHJ-rah-PAH-nah-yay nah-MAH', 'om_vajrapanaye_namah.mp3', 'https://paulwagner.com', 'Vajrapani: the power of the awakened mind →', 'Vajrapani — "thunderbolt in hand" — is the bodhisattva of power. He represents the power of the awakened mind to cut through all obstacles.', 'lotus'),
  (216, 'ॐ नमो भगवते भैषज्यगुरु', 'Om Namo Bhagavate Bhaishajyaguru', 'Om, I bow to the blessed Medicine Buddha.', 'buddhist', 'Healing', 'OHM nah-MOH bhah-gah-VAH-tay bhay-SHAHJ-yah-GOO-roo', 'om_namo_bhagavate_bh.mp3', 'https://paulwagner.com', 'Medicine Buddha: the healing practice →', 'Bhaishajyaguru — "Medicine Buddha" — is the buddha of healing. His body is lapis lazuli blue, and he holds a medicine bowl.', 'lotus'),
  (217, 'वैडूर्यप्रभाराजाय', 'Vaiduryaprabharajaya', 'To the king of lapis lazuli light.', 'buddhist', 'Healing', 'vay-DOO-ryah-PRAH-bhah-RAH-jah-yah', 'vaiduryaprabharajaya.mp3', 'https://paulwagner.com', 'Lapis lazuli: the stone of the Medicine Buddha →', 'Part of the Medicine Buddha mantra. Vaidurya — "lapis lazuli" — is the deep blue stone that represents the clarity of the awakened mind.', 'lotus'),
  (218, 'तथागताय', 'Tathagataya', 'To the thus-gone one — the one who has gone to suchness.', 'buddhist', 'Suchness', 'tah-TAH-gah-tah-yah', 'tathagataya.mp3', 'https://paulwagner.com', 'Tathata: the Buddhist concept of suchness →', 'Tathagata — "thus-gone" or "thus-come" — is the Buddha\'s own name for himself. It points to the nature of reality: things are just as they are.', 'lotus'),
  (219, 'ॐ भेकन्द्जे भेकन्द्जे', 'Om Bekandze Bekandze', 'Om — eliminate, eliminate — the pain of illness.', 'buddhist', 'Healing', 'OHM bay-KAHN-dzay bay-KAHN-dzay', 'om_bekandze_bekandze.mp3', 'https://paulwagner.com', 'The Medicine Buddha mantra: healing body and mind →', 'The heart of the Medicine Buddha mantra. Bekandze means "eliminate pain" — the mantra is said to heal both physical illness and the illness of ignorance.', 'lotus'),
  (220, 'महाभेकन्द्जे राद्जा समुद्गते स्वाहा', 'Maha Bekandze Radza Samudgate Svaha', 'Great elimination — king — the supreme arising — so be it.', 'buddhist', 'Complete Healing', 'mah-HAH bay-KAHN-dzay RAHD-zah sah-mood-GAH-tay svah-HAH', 'maha_bekandze_radza.mp3', 'https://paulwagner.com', 'The complete Medicine Buddha practice →', 'The conclusion of the Medicine Buddha mantra. Samudgate — "supreme arising" — points to the arising of the awakened mind that heals all.', 'lotus'),
  (221, 'ॐ नमो भगवते अमितायुषे', 'Om Namo Bhagavate Amitayushe', 'Om, I bow to the blessed one of infinite life.', 'buddhist', 'Longevity', 'OHM nah-MOH bhah-gah-VAH-tay ah-mee-TAH-yoo-shay', 'om_namo_bhagavate_am_d221.mp3', 'https://paulwagner.com', 'Amitayus: the Buddha of infinite life →', 'Amitayus — "infinite life" — is the longevity aspect of Amitabha Buddha. This mantra is chanted for long life and the extension of the teaching.', 'lotus'),
  (222, 'ॐ अमरणि जीवन्तये स्वाहा', 'Om Amarani Jivantaye Svaha', 'Om — immortal life — living — so be it.', 'buddhist', 'Life Force', 'OHM ah-mah-RAH-nih jee-VAHN-tah-yay svah-HAH', 'om_amarani_jivantaye.mp3', 'https://paulwagner.com', 'The deathless: what the Buddha meant by nirvana →', 'The Amitayus mantra. Amarani — "immortal" — refers not to physical immortality but to the deathless nature of the awakened mind.', 'lotus'),
  (223, 'ॐ कपिलाय नमः', 'Om Kapilaya Namah', 'Om, I bow to Kapila — the tawny-colored Ganesha of cosmic knowledge.', 'vedic_ganesha', 'Cosmic Knowledge', 'OHM kah-PIH-lah-yah nah-MAH', 'mantra-223.mp3', 'https://paulwagner.com', 'Kapila: the sage who founded Sankhya philosophy →', 'Kapila — "the tawny one" — is one of the twelve names of Ganesha. Kapila was also the name of the great sage who founded Sankhya philosophy, the science of cosmic enumeration.', 'seed_of_life'),
  (224, 'ॐ बोधिचित्त उत्पादयामि', 'Om Bodhicitta Utpadayami', 'Om, I generate the awakening mind.', 'buddhist', 'Awakening', 'OHM BOH-dhih-chiht-tah oot-PAH-dah-YAH-mih', 'om_bodhicitta_utpada.mp3', 'https://paulwagner.com', 'Bodhicitta: the most precious mind →', 'Bodhicitta — "awakening mind" — is the aspiration to achieve enlightenment for the benefit of all beings. It is the heart of Mahayana Buddhism.', 'lotus'),
  (225, 'ॐ नमो भगवते प्रज्ञापारमिताये', 'Om Namo Bhagavate Prajnaparamitaye', 'Om, I bow to the blessed perfection of wisdom.', 'buddhist', 'Wisdom', 'OHM nah-MOH bhah-gah-VAH-tay PRAHJ-nyah-PAH-rah-mih-TAH-yay', 'om_namo_bhagavate_pr.mp3', 'https://paulwagner.com', 'Prajnaparamita: the mother of all buddhas →', 'Prajnaparamita — "perfection of wisdom" — is personified as a goddess and is the "mother of all buddhas." The Heart Sutra is her teaching.', 'lotus'),
  (226, 'ॐ नमो भगवते अक्षोभ्याय', 'Om Namo Bhagavate Akshobhyaya', 'Om, I bow to the blessed Akshobhya — the imperturbable.', 'buddhist', 'Imperturbability', 'OHM nah-MOH bhah-gah-VAH-tay ahk-SHOH-bhyah-yah', 'om_namo_bhagavate_ak.mp3', 'https://paulwagner.com', 'The five dhyani buddhas: a complete map of awakening →', 'Akshobhya — "imperturbable" — is the buddha of the east, representing mirror-like wisdom. His dark blue color represents the depth of the awakened mind.', 'lotus'),
  (227, 'ॐ नमो भगवते रत्नसम्भवाय', 'Om Namo Bhagavate Ratnasambhavaya', 'Om, I bow to the blessed Ratnasambhava — the jewel-born.', 'buddhist', 'Abundance', 'OHM nah-MOH bhah-gah-VAH-tay raht-nah-SAHM-bhah-vah-yah', 'om_namo_bhagavate_ra.mp3', 'https://paulwagner.com', 'Ratnasambhava: the wisdom of equality →', 'Ratnasambhava — "jewel-born" — is the buddha of the south, representing the wisdom of equality. All beings are equally precious jewels.', 'lotus'),
  (228, 'ॐ नमो भगवते अमोघसिद्धये', 'Om Namo Bhagavate Amoghasiddhaye', 'Om, I bow to the blessed Amoghasiddhi — the infallible accomplisher.', 'buddhist', 'Accomplishment', 'OHM nah-MOH bhah-gah-VAH-tay ah-MOH-ghah-SID-dhah-yay', 'om_namo_bhagavate_am_d228.mp3', 'https://paulwagner.com', 'Amoghasiddhi: the all-accomplishing wisdom →', 'Amoghasiddhi — "infallible accomplishment" — is the buddha of the north, representing all-accomplishing wisdom.', 'lotus'),
  (229, 'ॐ नमो भगवते वैरोचनाय', 'Om Namo Bhagavate Vairochana', 'Om, I bow to the blessed Vairochana — the illuminator.', 'buddhist', 'Illumination', 'OHM nah-MOH bhah-gah-VAH-tay vay-ROH-chah-nah', 'om_namo_bhagavate_va_d229.mp3', 'https://paulwagner.com', 'Vairochana: the central buddha of the mandala →', 'Vairochana — "the illuminator" — is the central buddha of the five dhyani buddhas, representing the dharmadhatu wisdom — the wisdom of all-encompassing space.', 'lotus'),
  (230, 'ॐ आह्राह् हूँ', 'Om Ah Ra Pa Ca Na Dhih Dhih Dhih', 'Om — the wisdom syllables — wisdom, wisdom, wisdom.', 'buddhist', 'Wisdom', 'OHM ah rah pah chah nah dhee dhee dhee', 'om_ah_ra_pa_ca_na_dh.mp3', 'https://paulwagner.com', 'Prajna: the wisdom that liberates →', 'The extended Manjushri mantra with triple Dhih. Dhih is the seed syllable of wisdom — repeating it three times intensifies the awakening of prajna.', 'lotus'),
  (231, 'ॐ सुप्रतिष्ठित स्वाहा', 'Om Supratishthita Svaha', 'Om — well-established — so be it.', 'buddhist', 'Stability', 'OHM soo-prah-TISH-thih-tah svah-HAH', 'om_supratishthita_sv.mp3', 'https://paulwagner.com', 'Establishing a daily practice: the Buddhist approach →', 'Supratishthita — "well-established" — is a dharani for establishing the practice firmly. Svaha seals the intention.', 'lotus'),
  (232, 'ॐ धरणी धरणी स्वाहा', 'Om Dharani Dharani Svaha', 'Om — earth-holder, earth-holder — so be it.', 'buddhist', 'Grounding', 'OHM dhah-RAH-nih dhah-RAH-nih svah-HAH', 'om_dharani_dharani_s.mp3', 'https://paulwagner.com', 'Dharani: the mantras that hold the earth →', 'Dharani means both "earth" and "that which holds." This mantra grounds the practice in the earth of reality.', 'lotus'),
  (233, 'ॐ नमो भगवते वज्रपाणये', 'Om Namo Bhagavate Vajrapanaye', 'Om, I bow to the blessed Vajrapani.', 'buddhist', 'Power', 'OHM nah-MOH bhah-gah-VAH-tay VAHJ-rah-PAH-nah-yay', 'om_namo_bhagavate_va_d233.mp3', 'https://paulwagner.com', 'The three poisons: greed, hatred, and delusion →', 'Vajrapani\'s thunderbolt cuts through the three poisons: greed, hatred, and delusion. This mantra invokes the power to overcome inner obstacles.', 'lotus'),
  (234, 'ॐ नमो भगवते कुरुकुल्लायै', 'Om Namo Bhagavate Kurukulle', 'Om, I bow to the blessed Kurukulle — the goddess of enchantment.', 'buddhist', 'Attraction', 'OHM nah-MOH bhah-gah-VAH-tay koo-roo-KOOL-lay', 'om_namo_bhagavate_ku.mp3', 'https://paulwagner.com', 'Kurukulle: the goddess who draws beings to the Dharma →', 'Kurukulle is a tantric goddess who enchants and magnetizes — drawing beings toward the Dharma through the power of love.', 'lotus'),
  (235, 'ॐ नमो भगवते चुन्द्रायै', 'Om Namo Bhagavate Cundrayai', 'Om, I bow to the blessed Cunda — the goddess of awakening.', 'buddhist', 'Awakening', 'OHM nah-MOH bhah-gah-VAH-tay CHOON-drah-yay', 'om_namo_bhagavate_cu.mp3', 'https://paulwagner.com', 'The female bodhisattvas: wisdom in feminine form →', 'Cunda (or Chunda) is a bodhisattva associated with the awakening mind. She is depicted with multiple arms representing her many activities.', 'lotus'),
  (236, 'ॐ नमो भगवते वज्रसारप्रमर्दने', 'Om Namo Bhagavate Vajrasarapramardane', 'Om, I bow to the crusher of the vajra essence.', 'buddhist', 'Purification', 'OHM nah-MOH bhah-gah-VAH-tay VAHJ-rah-SAH-rah-prah-MAHR-dah-nay', 'om_namo_bhagavate_va_d236.mp3', 'https://paulwagner.com', 'Karma: what it really means and how to purify it →', 'A powerful purification dharani. Pramardane — "crusher" — refers to the crushing of karmic obscurations.', 'lotus'),
  (237, 'ॐ सर्वपापविशोधन', 'Om Sarvapapavishoshana', 'Om — purifier of all sins.', 'buddhist', 'Purification', 'OHM sahr-vah-PAH-pah-vih-SOH-shah-nah', 'om_sarvapapavishosha.mp3', 'https://paulwagner.com', 'Purification practices in Buddhism →', 'A dharani for purifying all negative karma. Vishoshana — "drying up" — suggests that negative karma is dried up like water in sunlight.', 'lotus'),
  (238, 'ॐ नमो भगवते सर्वतथागत', 'Om Namo Bhagavate Sarvatathagata', 'Om, I bow to all the blessed thus-gone ones.', 'buddhist', 'Reverence', 'OHM nah-MOH bhah-gah-VAH-tay sahr-vah-tah-TAH-gah-tah', 'om_namo_bhagavate_sa_d238.mp3', 'https://paulwagner.com', 'The infinite buddhas: the Buddhist vision of awakening →', 'A universal salutation to all buddhas of all times and directions. The awakened ones are infinite in number.', 'lotus'),
  (239, 'ॐ धर्मधातु स्वभाव', 'Om Dharmadhatu Svabhava', 'Om — the nature of the dharma realm.', 'buddhist', 'Nature of Mind', 'OHM DHAHR-mah-DAH-too svah-BHAH-vah', 'om_dharmadhatu_svabh.mp3', 'https://paulwagner.com', 'Dharmadhatu: the realm of truth →', 'Dharmadhatu — "dharma realm" — is the totality of all phenomena as they truly are. Svabhava — "own nature" — points to the intrinsic nature of mind.', 'lotus'),
  (240, 'ॐ स्वभाव शुद्धाः सर्वधर्माः', 'Om Svabhava Shuddha Sarvadharmah', 'Om — by nature pure are all phenomena.', 'buddhist', 'Purity', 'OHM svah-BHAH-vah SHOO-dhah sahr-vah-DHAHR-mah', 'om_svabhava_shuddha.mp3', 'https://paulwagner.com', 'Emptiness: the most misunderstood Buddhist teaching →', 'The emptiness mantra — all phenomena are pure by nature. This is the Madhyamaka view: nothing is inherently defiled.', 'lotus'),
  (241, 'स्वभाव शुद्धो ऽहम्', 'Svabhava Shuddho\'ham', 'I am pure by nature.', 'buddhist', 'Purity', 'svah-BHAH-vah SHOO-dhoh-hahm', 'svabhava_shuddhoham.mp3', 'https://paulwagner.com', 'Buddha nature: the purity that was always there →', 'The personal application of the emptiness mantra. Your true nature is pure — not because you have purified it, but because it was never defiled.', 'lotus'),
  (242, 'ॐ नमो भगवते तथागत', 'Om Namo Bhagavate Tathagata', 'Om, I bow to the blessed thus-gone one.', 'buddhist', 'Suchness', 'OHM nah-MOH bhah-gah-VAH-tay tah-TAH-gah-tah', 'om_namo_bhagavate_ta.mp3', 'https://paulwagner.com', 'Tathagata: the Buddha\'s most profound name →', 'A simple, universal invocation of the Buddha. Tathagata — "thus-gone" — points to the nature of awakening: going beyond all concepts.', 'lotus'),
  (243, 'ॐ भव भव महाभव', 'Om Bhava Bhava Mahabhava', 'Om — become, become, greatly become.', 'buddhist', 'Becoming', 'OHM BHAH-vah BHAH-vah mah-hah-BHAH-vah', 'om_bhava_bhava_mahab.mp3', 'https://paulwagner.com', 'Impermanence: the Buddhist teaching on change →', 'A mantra of transformation. Bhava — "becoming" — is the process of continuous change. The mantra invites full participation in the process of becoming.', 'lotus'),
  (244, 'ॐ सम्बोधि सम्बोधि', 'Om Sambodhi Sambodhi', 'Om — complete awakening, complete awakening.', 'buddhist', 'Awakening', 'OHM sahm-BOH-dhee sahm-BOH-dhee', 'om_sambodhi_sambodhi.mp3', 'https://paulwagner.com', 'Sambodhi: what complete awakening actually means →', 'Sambodhi — "complete awakening" — is the full enlightenment of a buddha. Repeating it twice affirms the aspiration for complete awakening.', 'lotus'),
  (245, 'ॐ बोधि बोधि महाबोधि', 'Om Bodhi Bodhi Mahabodhi', 'Om — awakening, awakening, great awakening.', 'buddhist', 'Awakening', 'OHM BOH-dhee BOH-dhee mah-hah-BOH-dhee', 'om_bodhi_bodhi_mahab.mp3', 'https://paulwagner.com', 'The stages of awakening in Buddhism →', 'A mantra of progressive awakening. Bodhi — "awakening" — grows from individual to great, from partial to complete.', 'lotus'),
  (246, 'ॐ नमो भगवते अवलोकितेश्वराय', 'Om Namo Bhagavate Avalokiteshvaraya', 'Om, I bow to the blessed Avalokiteshvara — the one who hears all cries.', 'buddhist', 'Compassion', 'OHM nah-MOH bhah-gah-VAH-tay ah-vah-loh-kih-TAYSH-vah-rah-yah', 'om_namo_bhagavate_av.mp3', 'https://paulwagner.com', 'Avalokiteshvara: the bodhisattva of universal compassion →', 'Avalokiteshvara — "the one who looks down with compassion" — is the bodhisattva who hears all cries of suffering and responds with compassion.', 'lotus'),
  (247, 'ॐ सर्वज्ञाय नमः', 'Om Sarvajnaya Namah', 'Om, I bow to the all-knowing one.', 'buddhist', 'Omniscience', 'OHM sahr-VAHJ-nyah-yah nah-MAH', 'om_sarvajnaya_namah.mp3', 'https://paulwagner.com', 'Omniscience: the Buddhist understanding →', 'Sarvajnaya — "all-knowing" — is an epithet of the Buddha. Omniscience is not supernatural; it is the natural result of a completely purified mind.', 'lotus'),
  (248, 'ॐ नमो भगवते मैत्रेयाय', 'Om Namo Bhagavate Maitreya', 'Om, I bow to the blessed Maitreya — the future Buddha of loving-kindness.', 'buddhist', 'Loving-Kindness', 'OHM nah-MOH bhah-gah-VAH-tay my-TRAY-yah', 'om_namo_bhagavate_ma.mp3', 'https://paulwagner.com', 'Maitreya: the future Buddha of loving-kindness →', 'Maitreya — "the loving one" — is the future Buddha who will appear when the Dharma has been forgotten. His name is the root of the word "metta."', 'lotus'),
  (249, 'ॐ नमो भगवते क्षितिगर्भाय', 'Om Namo Bhagavate Kshitigarbhaya', 'Om, I bow to the blessed Kshitigarbha — the earth treasury.', 'buddhist', 'Compassion', 'OHM nah-MOH bhah-gah-VAH-tay kshih-tih-GAHR-bhah-yah', 'om_namo_bhagavate_ks.mp3', 'https://paulwagner.com', 'Kshitigarbha: the bodhisattva who descends to hell →', 'Kshitigarbha — "earth treasury" — is the bodhisattva who vowed to save all beings from the hell realms before becoming a buddha.', 'lotus'),
  (250, 'ॐ सम्पद्यन्ते स्वाहा', 'Om Sampadyante Svaha', 'Om — may it be accomplished — so be it.', 'buddhist', 'Accomplishment', 'OHM sahm-PAHD-yahn-tay svah-HAH', 'om_sampadyante_svaha.mp3', 'https://paulwagner.com', 'Sealing a practice: the importance of dedication →', 'A completion mantra. Sampadyante — "may it be accomplished" — seals any practice or intention with the wish for its fulfillment.', 'lotus'),
  (251, 'ੴ ਸਤਿ ਨਾਮੁ', 'Ik Onkar Sat Nam', 'One God — True Name.', 'sikh', 'Unity', 'ik OHN-kahr saht nahm', 'ik_onkar_sat_nam.mp3', 'https://paulwagner.com', 'The Mool Mantar: Sikhism\'s most sacred teaching →', 'The Mool Mantar — the root mantra of Sikhism, composed by Guru Nanak. Ik Onkar — "One God" — is the foundational truth of Sikh theology.', 'seed_of_life'),
  (252, 'ਕਰਤਾ ਪੁਰਖੁ', 'Karta Purakh', 'The Creator Being.', 'sikh', 'Creation', 'KAHR-tah POO-rahkh', 'karta_purakh.mp3', 'https://paulwagner.com', 'Karta Purakh: the personal God of Sikhism →', 'From the Mool Mantar. Karta — "creator" — Purakh — "being" or "person." The divine is not an abstract force but a personal creator.', 'seed_of_life'),
  (253, 'ਨਿਰਭਉ ਨਿਰਵੈਰੁ', 'Nirbhau Nirvair', 'Without fear, without enmity.', 'sikh', 'Fearlessness', 'nih-BHOW nih-VAIR', 'nirbhau_nirvair.mp3', 'https://paulwagner.com', 'Nirbhau: the fearless God of Guru Nanak →', 'From the Mool Mantar. The divine has no fear and no enemies. Meditating on these qualities transforms the practitioner.', 'seed_of_life'),
  (254, 'ਅਕਾਲ ਮੂਰਤਿ', 'Akal Murat', 'Timeless form — beyond time and death.', 'sikh', 'Eternity', 'ah-KAHL MOO-raht', 'akal_murat.mp3', 'https://paulwagner.com', 'Akal: the timeless God of Sikhism →', 'From the Mool Mantar. Akal — "beyond time" — Murat — "form." The divine is the timeless presence that underlies all temporal forms.', 'seed_of_life'),
  (255, 'ਅਜੂਨੀ ਸੈਭੰ', 'Ajuni Saibhang', 'Unborn, self-illumined.', 'sikh', 'Self-Sufficiency', 'ah-JOO-nih SAY-bhahng', 'ajuni_saibhang.mp3', 'https://paulwagner.com', 'Saibhang: the self-illumined nature of God →', 'From the Mool Mantar. The divine was not born and does not need anything outside itself. Saibhang — "self-illumined" — the divine is its own light.', 'seed_of_life'),
  (256, 'ਗੁਰ ਪ੍ਰਸਾਦਿ', 'Gur Prasad', 'By the grace of the Guru.', 'sikh', 'Grace', 'goor prah-SAHD', 'gur_prasad.mp3', 'https://paulwagner.com', 'Gur Prasad: the grace that makes everything possible →', 'The final phrase of the Mool Mantar. All spiritual realization comes by the grace of the Guru — not by personal effort alone.', 'seed_of_life'),
  (257, 'ਵਾਹਿਗੁਰੂ', 'Waheguru', 'Wondrous Guru — the divine that fills us with wonder.', 'sikh', 'Wonder', 'WAH-hay-goo-roo', 'waheguru.mp3', 'https://paulwagner.com', 'Waheguru: the wonder at the heart of Sikhism →', 'The most important mantra in Sikhism. Wahe — "wondrous" — Guru — "teacher." The divine is the teacher who fills us with wonder.', 'seed_of_life'),
  (258, 'ਸਤਿ ਨਾਮੁ ਵਾਹਿਗੁਰੂ', 'Sat Nam Waheguru', 'True Name — Wondrous Guru.', 'sikh', 'Truth', 'saht nahm WAH-hay-goo-roo', 'sat_nam_waheguru.mp3', 'https://paulwagner.com', 'Sat Nam: the true name of God →', 'The most common Sikh mantra combination. Sat Nam — "True Name" — is the identity of the divine. Waheguru is the expression of wonder at that truth.', 'seed_of_life'),
  (259, 'ਸਤਿ ਸ੍ਰੀ ਅਕਾਲ', 'Sat Sri Akal', 'True, great, and timeless.', 'sikh', 'Truth', 'saht sree ah-KAHL', 'sat_sri_akal.mp3', 'https://paulwagner.com', 'Sat Sri Akal: the Sikh greeting and its meaning →', 'The Sikh greeting and battle cry. Sri — "great" or "radiant" — Akal — "timeless." A reminder that truth is eternal.', 'seed_of_life'),
  (260, 'ਨਾਨਕ ਨਾਮ ਚੜ੍ਹਦੀ ਕਲਾ', 'Nanak Nam Chardi Kala', 'Nanak, through the Name, may there be ever-rising spirit.', 'sikh', 'Optimism', 'NAH-nahk nahm CHAHR-dee kah-LAH', 'nanak_nam_chardi_kal.mp3', 'https://paulwagner.com', 'Chardi Kala: the Sikh practice of eternal optimism →', 'Chardi Kala — "ever-rising spirit" — is the Sikh concept of eternal optimism. No matter what happens, the spirit rises. This is the Sikh response to adversity.', 'seed_of_life'),
  (261, 'ਤੇਰੇ ਭਾਣੇ ਸਰਬਤ ਦਾ ਭਲਾ', 'Tere Bhane Sarbat Da Bhala', 'In your will, may all prosper.', 'sikh', 'Universal Welfare', 'TAY-ray BHAH-nay SAHR-baht dah BHAH-lah', 'tere_bhane_sarbat_da.mp3', 'https://paulwagner.com', 'Ardas: the Sikh prayer for all humanity →', 'The Ardas prayer\'s closing line. Sarbat — "all" — Da Bhala — "welfare." The Sikh prayer always ends with a wish for the welfare of all humanity.', 'seed_of_life'),
  (262, 'ਸਿਮਰਨ ਸਿਮਰਨ ਸਿਮਰਨ', 'Simran Simran Simran', 'Remembrance, remembrance, remembrance.', 'sikh', 'Remembrance', 'SIM-rahn SIM-rahn SIM-rahn', 'simran_simran_simran.mp3', 'https://paulwagner.com', 'Simran: the Sikh practice of divine remembrance →', 'Simran — "remembrance" or "meditation" — is the central Sikh practice. To remember God\'s name in every breath is the highest spiritual discipline.', 'seed_of_life'),
  (263, 'ਹਰਿ ਹਰਿ ਹਰਿ ਹਰਿ', 'Har Har Har Har', 'God, God, God, God — the creative infinity.', 'sikh', 'Creativity', 'hahr hahr hahr hahr', 'har_har_har_har.mp3', 'https://paulwagner.com', 'Har: the creative name of God in Sikhism →', 'Har is the Sikh name for God as the creative force. Repeating it activates the navel center and the creative power of the divine.', 'seed_of_life'),
  (264, 'ਹਰਿ ਨਾਮੁ ਜਪਹੁ', 'Har Nam Japahu', 'Chant the name of God.', 'sikh', 'Practice', 'hahr nahm JAH-pah-hoo', 'har_nam_japahu.mp3', 'https://paulwagner.com', 'Japa: the practice of mantra repetition →', 'From the Guru Granth Sahib. Japahu — "chant" — is the imperative form. The Guru\'s instruction is direct: chant the name.', 'seed_of_life'),
  (265, 'ਰਾਮ ਰਾਮ ਰਾਮ ਰਾਮ', 'Ram Ram Ram Ram', 'Ram, Ram, Ram, Ram — the divine joy.', 'sikh', 'Joy', 'rahm rahm rahm rahm', 'ram_ram_ram_ram.mp3', 'https://paulwagner.com', 'Ram in Sikhism: the all-pervasive divine →', 'In Sikhism, Ram is not just the avatar but the divine name meaning "the one who permeates all." The Gurus used many divine names interchangeably.', 'seed_of_life'),
  (266, 'ਗੋਬਿੰਦ ਗੋਬਿੰਦ ਗੋਬਿੰਦ ਸੰਗਿ', 'Gobind Gobind Gobind Sang', 'Gobind, Gobind, Gobind — in the company of God.', 'sikh', 'Companionship', 'GOH-bind GOH-bind GOH-bind sahng', 'gobind_gobind_gobind.mp3', 'https://paulwagner.com', 'Sangat: the Sikh community of truth →', 'From the Guru Granth Sahib. Gobind — "sustainer of the world" — is repeated three times, then "sang" — "in the company of." We are never alone.', 'seed_of_life'),
  (267, 'ਨਾਮੁ ਜਪਤ ਅਰਪੋ ਤਨੁ ਮਨੁ', 'Nam Japat Arpo Tan Man', 'Chanting the Name, offer body and mind.', 'sikh', 'Surrender', 'nahm JAH-paht AHR-poh tahn mahn', 'nam_japat_arpo_tan_m.mp3', 'https://paulwagner.com', 'Total surrender: the Sikh path of devotion →', 'From the Guru Granth Sahib. The complete offering in Sikhism is not just words but the whole self — body and mind — surrendered to the divine name.', 'seed_of_life'),
  (268, 'ਸਾਸ ਸਾਸ ਸਿਮਰਹੁ ਗੋਬਿੰਦ', 'Sas Sas Simrahu Gobind', 'With every breath, remember Gobind.', 'sikh', 'Breath Practice', 'sahs sahs SIM-rah-hoo GOH-bind', 'sas_sas_simrahu_gobi.mp3', 'https://paulwagner.com', 'Breath as prayer: the Sikh practice of Sas Sas →', 'From the Guru Granth Sahib. Sas — "breath." The Sikh practice of remembering God with every breath transforms ordinary breathing into prayer.', 'seed_of_life'),
  (269, 'ਮਨ ਤੂੰ ਜੋਤਿ ਸਰੂਪੁ ਹੈ', 'Man Tu Jot Sarup Hai', 'O mind, you are the image of divine light.', 'sikh', 'Self-Realization', 'mahn too joht sah-ROOP hay', 'man_tu_jot_sarup_hai.mp3', 'https://paulwagner.com', 'Jot Sarup: the light within you →', 'From the Guru Granth Sahib. Jot — "light" — Sarup — "form" or "image." The mind is not the enemy but the image of divine light.', 'seed_of_life'),
  (270, 'ਅਪਣਾ ਮੂਲੁ ਪਛਾਣੁ', 'Apna Mul Pachhan', 'Recognize your own origin.', 'sikh', 'Self-Knowledge', 'ahp-NAH mool pah-CHAHN', 'apna_mul_pachhan.mp3', 'https://paulwagner.com', 'Mul: returning to the root of your being →', 'From the Guru Granth Sahib. Mul — "root" or "origin." The Guru\'s instruction: know where you come from. Your origin is divine.', 'seed_of_life'),
  (271, 'ਜਿਉ ਜਿਉ ਤੇਰੀ ਰਜਾਇ', 'Jio Jio Teri Raza', 'As is your will, so be it.', 'sikh', 'Acceptance', 'jee-OH jee-OH TAY-ree rah-ZAH', 'jio_jio_teri_raza.mp3', 'https://paulwagner.com', 'Raza: the Sikh practice of divine will acceptance →', 'From the Guru Granth Sahib. Raza — "will" or "pleasure." Complete acceptance of the divine will is the highest Sikh spiritual state.', 'seed_of_life'),
  (272, 'ਨਾਨਕ ਦਾਸ ਤੇਰੇ ਦਰ ਕਾ', 'Nanak Das Tere Dar Ka', 'Nanak is the servant at your door.', 'sikh', 'Humility', 'NAH-nahk dahs TAY-ray dahr kah', 'nanak_das_tere_dar_k.mp3', 'https://paulwagner.com', 'Guru Nanak: the servant who became the teacher →', 'Guru Nanak\'s signature of humility. Das — "servant." The greatest teacher called himself a servant at the divine door.', 'seed_of_life'),
  (273, 'ਤੁਧੁ ਬਿਨੁ ਦੂਜਾ ਨਾਹੀ ਕੋਇ', 'Tudh Bin Duja Nahi Koi', 'Without you, there is no other.', 'sikh', 'Oneness', 'too-DHOO bin DOO-jah nah-HEE koh-EE', 'tudh_bin_duja_nahi_k.mp3', 'https://paulwagner.com', 'Sikh non-dualism: there is only one →', 'From the Guru Granth Sahib. A declaration of non-duality: there is only God. Everything else is the play of the one divine reality.', 'seed_of_life'),
  (274, 'ਸਰਬ ਕਲਾ ਭਰਪੂਰ', 'Sarab Kala Bharpoor', 'Fully pervading all with all powers.', 'sikh', 'Omnipresence', 'sah-RAHB kah-LAH bhar-POOR', 'sarab_kala_bharpoor.mp3', 'https://paulwagner.com', 'The omnipresent God of the Guru Granth Sahib →', 'From the Guru Granth Sahib. Sarab — "all" — Kala — "powers" — Bharpoor — "fully pervading." The divine is fully present everywhere with all its powers.', 'seed_of_life'),
  (275, 'ॐ', 'Om', 'The primordial sound — the vibration from which all creation arises.', 'universal', 'Source', 'OHM (hold for 5-7 seconds)', 'om.mp3', 'https://paulwagner.com', 'The physics of Om: why it is the primordial sound →', 'Om is the first sound — the vibration of pure consciousness before it becomes words or thoughts. It contains all sounds within it.', 'seed_of_life'),
  (276, 'ॐ ॐ ॐ', 'Om Om Om', 'Three Oms — for body, speech, and mind.', 'universal', 'Integration', 'OHM... OHM... OHM... (pause between each)', 'om_om_om.mp3', 'https://paulwagner.com', 'The three Oms: a complete purification practice →', 'Three Oms purify the three aspects of our being: the physical body, speech and breath, and the mind. A complete practice in three sounds.', 'seed_of_life'),
  (277, 'ॐ शान्तिः शान्तिः शान्तिः', 'Om Shantih Shantih Shantih', 'Om — peace, peace, peace.', 'universal', 'Peace', 'OHM SHAHN-tih SHAHN-tih SHAHN-tih', 'om_shantih_shantih_s.mp3', 'https://paulwagner.com', 'The three sources of suffering and their antidote →', 'The universal peace invocation ending all Vedic prayers. Three repetitions address the three sources of suffering: adhyatmika (self), adhibhautika (others), adhidaivika (cosmos).', 'lotus'),
  (278, 'सोऽहम्', 'So\'ham', 'I am that — the breath itself is the mantra.', 'universal', 'Identity', 'SOH-hahm (So on inhale, Ham on exhale)', 'soham.mp3', 'https://paulwagner.com', 'So\'ham: the mantra you\'ve been chanting since birth →', 'So\'ham is the natural sound of the breath: So on the inhale, Ham on the exhale. The breath itself is saying "I am that" 21,600 times per day.', 'seed_of_life'),
  (279, 'हंसः', 'Hamsa', 'The swan — the breath — I am that.', 'universal', 'Breath', 'HAHM-sah (Ham on exhale, Sa on inhale)', 'hamsa.mp3', 'https://paulwagner.com', 'Hamsa: the swan of discernment →', 'Hamsa — "swan" or "I am that" — is So\'ham reversed. The swan is the symbol of the discriminating mind that separates milk from water.', 'seed_of_life'),
  (280, 'अहम् ब्रह्मास्मि', 'Aham Brahmasmi', 'I am Brahman — I am the infinite.', 'universal', 'Self-Realization', 'AH-hahm BRAH-mahs-mih', 'aham_brahmasmi.mp3', 'https://paulwagner.com', 'The four mahavakyas: the Upanishads\' greatest declarations →', 'One of the four mahavakyas — great sayings — of the Upanishads. From the Brihadaranyaka Upanishad. The direct declaration of identity with the infinite.', 'sri_yantra'),
  (281, 'तत् त्वम् असि', 'Tat Tvam Asi', 'That thou art — you are that infinite reality.', 'universal', 'Non-Duality', 'taht tvahm AH-see', 'tat_tvam_asi.mp3', 'https://paulwagner.com', 'Tat tvam asi: the teaching that changes everything →', 'The second mahavakya from the Chandogya Upanishad. The teacher\'s declaration to the student: you are not separate from the infinite.', 'sri_yantra'),
  (282, 'प्रज्ञानं ब्रह्म', 'Prajnanam Brahma', 'Consciousness is Brahman — awareness is the infinite.', 'universal', 'Consciousness', 'PRAHJ-nyah-nahm BRAH-mah', 'prajnanam_brahma.mp3', 'https://paulwagner.com', 'Consciousness as the ground of being →', 'The third mahavakya from the Aitareya Upanishad. Prajna — "consciousness" or "awareness" — is identified with the infinite ground of being.', 'sri_yantra'),
  (283, 'अयम् आत्मा ब्रह्म', 'Ayam Atma Brahma', 'This self is Brahman — the individual self is the universal self.', 'universal', 'Unity', 'AH-yahm AHT-mah BRAH-mah', 'ayam_atma_brahma.mp3', 'https://paulwagner.com', 'The four mahavakyas: the great declarations of non-duality →', 'The fourth mahavakya from the Mandukya Upanishad. The individual self (atman) is declared identical to the universal ground of being (brahman). The simplest and most direct of the four great sayings.', 'sri_yantra'),
  (284, '', 'Burn the mask or be buried in it', 'Burn the mask or be buried in it', 'universal', 'Liberation', '', '', 'https://paulwagner.com', 'The sacred art of letting go →', 'Letting go is not loss — it is making space for grace. Every release is an act of trust in the divine unfolding of your life.', 'seed_of_life'),
  (285, '', 'I am not this body or mind', 'I am not this body or mind', 'universal', 'Courage', '', '', 'https://paulwagner.com', 'Why an open heart is your greatest strength →', 'An open heart is the most powerful force in the universe. When you lead with love, fear dissolves like shadows in sunlight.', 'seed_of_life'),
  (286, '', 'The false self crumbles — I remain', 'The false self crumbles — I remain', 'universal', 'Surrender', '', '', 'https://paulwagner.com', 'Surrendering to divine timing →', 'Your life is not random — it is orchestrated by a wisdom far greater than the mind can comprehend. Trust the process.', 'seed_of_life'),
  (287, 'ॐ सच्चिदानन्द', 'Om Satchidananda', 'Om — existence, consciousness, bliss.', 'universal', 'Bliss', 'OHM saht-chid-AH-nahn-dah', 'om_satchidananda.mp3', 'https://paulwagner.com', 'Satchidananda: the nature of ultimate reality →', 'Sat-Chit-Ananda — the three qualities of Brahman: pure existence, pure consciousness, and pure bliss. This is the nature of ultimate reality.', 'sri_yantra'),
  (288, '', 'I invented this Me — I can dissolve it', 'I invented this Me — I can dissolve it', 'universal', 'Awareness', '', '', 'https://paulwagner.com', 'The observer effect in spiritual practice →', 'The moment you realize you are watching your thoughts, you have stepped into your true nature — pure consciousness itself.', 'sri_yantra'),
  (289, '', 'Nothing real about me can be diminished', 'Nothing real about me can be diminished', 'universal', 'Inner Peace', '', '', 'https://paulwagner.com', 'Finding peace in the eye of the storm →', 'Peace is not the absence of chaos — it is the presence of awareness. You can access it anywhere, anytime, by turning inward.', 'lotus'),
  (290, '', 'I am nothing — and everything at once', 'I am nothing — and everything at once', 'universal', 'Unity', '', '', 'https://paulwagner.com', 'The Vedantic truth of oneness →', 'Separation is the great illusion. The same divine spark that animates your heart beats in every creature on Earth.', 'flower_of_life'),
  (291, '', 'The ego served me — now I release it', 'The ego served me — now I release it', 'universal', 'Abundance', '', '', 'https://paulwagner.com', 'Aligning with the flow of abundance →', 'Abundance is not something you chase — it is something you align with. When you vibrate at the frequency of gratitude, abundance finds you.', 'lotus'),
  (292, 'ॐ ऐं सरस्वत्यै नमः', 'Om Aim Sarasvatyai Namah', 'Om — seed of Saraswati — I bow to the goddess of wisdom.', 'universal', 'Wisdom', 'OHM aim sah-rahs-VAHT-yay nah-MAH', 'om_aim_sarasvatyai_n.mp3', 'https://paulwagner.com', 'Saraswati: the goddess of creative wisdom →', 'Saraswati is the goddess of learning, music, and wisdom. Aim is her seed syllable. This mantra is chanted before study and creative work.', 'lotus'),
  (293, 'ॐ दुं दुर्गायै नमः', 'Om Dum Durgayai Namah', 'Om — seed of Durga — I bow to the invincible one.', 'universal', 'Courage', 'OHM doom door-GAH-yay nah-MAH', 'om_dum_durgayai_nama.mp3', 'https://paulwagner.com', 'Durga: the warrior goddess within you →', 'Durga — "the invincible" — is the warrior goddess who protects against all evil. Dum is her seed syllable. This mantra invokes inner strength.', 'lotus'),
  (294, 'ॐ क्लीं कृष्णाय नमः', 'Om Klim Krishnaya Namah', 'Om — seed of attraction — I bow to Krishna.', 'universal', 'Love', 'OHM kleem krish-NAH-yah nah-MAH', 'om_klim_krishnaya_na.mp3', 'https://paulwagner.com', 'Klim: the seed syllable of divine love →', 'Klim is the seed syllable of attraction and love. This mantra invokes Krishna\'s quality of divine love — the love that draws all things toward the divine.', 'flower_of_life'),
  (295, '', 'I am the witness, not the chaos', 'I am the witness, not the chaos', 'universal', 'Self-Forgiveness', '', '', 'https://paulwagner.com', 'Why forgiveness is not what you think →', 'Self-forgiveness is not weakness — it is the bravest act of love. You cannot heal what you refuse to hold with compassion.', 'flower_of_life'),
  (296, 'ॐ तत् सत्', 'Om Tat Sat', 'Om — that — truth.', 'universal', 'Truth', 'OHM taht saht', 'om_tat_sat.mp3', 'https://paulwagner.com', 'Om Tat Sat: the three names of the absolute →', 'From the Bhagavad Gita. Om Tat Sat — the three designations of Brahman. Om is the sound, Tat is the pointer, Sat is the reality.', 'seed_of_life'),
  (297, '', 'The past is a cancelled check', 'The past is a cancelled check', 'universal', 'Self-Acceptance', '', '', 'https://paulwagner.com', 'The radical truth of self-acceptance →', 'The spiritual path is not about becoming someone new — it is about remembering who you have always been beneath the layers of conditioning.', 'flower_of_life'),
  (298, 'ॐ श्री रामाय नमः', 'Om Sri Ramaya Namah', 'Om — I bow to the radiant Ram.', 'universal', 'Virtue', 'OHM shree RAH-mah-yah nah-MAH', 'om_sri_ramaya_namah.mp3', 'https://paulwagner.com', 'Ram: the avatar of perfect virtue →', 'Ram — "the one who delights" — is the avatar of Vishnu who embodies dharma. Sri adds radiance and auspiciousness to the invocation.', 'flower_of_life'),
  (299, 'राम राम राम', 'Ram Ram Ram', 'Ram, Ram, Ram — the name that is the Vedas.', 'universal', 'Liberation', 'rahm rahm rahm', 'ram_ram_ram.mp3', 'https://paulwagner.com', 'Why Gandhi\'s last words were "Hey Ram" →', 'Gandhi\'s dying words were "Hey Ram." The name Ram is said to contain the essence of all the Vedas. Simple, direct, and infinitely deep.', 'flower_of_life'),
  (300, 'ॐ हनुमते नमः', 'Om Hanumate Namah', 'Om — I bow to Hanuman — the devoted servant.', 'universal', 'Devotion', 'OHM hah-noo-MAH-tay nah-MAH', 'om_hanumate_namah.mp3', 'https://paulwagner.com', 'Hanuman: the perfect devotee →', 'Hanuman is the embodiment of devotion, strength, and selfless service. His devotion to Ram is the model for all spiritual practice.', 'flower_of_life'),
  (301, 'ॐ श्री हनुमते नमः', 'Om Sri Hanumate Namah', 'Om — I bow to the radiant Hanuman.', 'universal', 'Strength', 'OHM shree hah-noo-MAH-tay nah-MAH', 'om_sri_hanumate_nama.mp3', 'https://paulwagner.com', 'Strength through devotion: Hanuman\'s secret →', 'Hanuman\'s strength comes from his devotion — not from ego or personal power. This mantra invokes strength that is rooted in love.', 'flower_of_life'),
  (302, '', 'I release what is not me — I find peace', 'I release what is not me — I find peace', 'universal', 'Inner Wisdom', '', '', 'https://paulwagner.com', 'The inner guru awakens →', 'Every external teacher points you back to the same truth — the guru within. Your own consciousness is the ultimate guide.', 'sri_yantra'),
  (303, '', 'Feel everything — then let it burn', 'Feel everything — then let it burn', 'universal', 'Presence', '', '', 'https://paulwagner.com', 'The sacred art of breathwork →', 'The breath is the bridge between body and spirit. Each conscious breath is a prayer, a return to the sacred now.', 'sri_yantra'),
  (304, '', 'I forgive to reclaim my own freedom', 'I forgive to reclaim my own freedom', 'universal', 'Trust', '', '', 'https://paulwagner.com', 'Trusting the cosmic embrace →', 'You are never alone. The same force that spins galaxies and grows forests is holding you right now.', 'sri_yantra'),
  (305, '', 'Bolt the door shut and walk away', 'Bolt the door shut and walk away', 'universal', 'Unconditional Love', '', '', 'https://paulwagner.com', 'Love as spiritual practice →', 'Unconditional love is not something you practice — it is what you are when you stop pretending to be something else.', 'sri_yantra'),
  (306, 'ॐ भूमि माता', 'Om Bhumi Mata', 'Om — Earth Mother.', 'universal', 'Earth', 'OHM BHOO-mih MAH-tah', 'om_bhumi_mata.mp3', 'https://paulwagner.com', 'Earth as mother: the universal teaching →', 'A universal invocation of the earth as mother. All spiritual traditions recognize the earth as sacred. We are born from her and return to her.', 'lotus'),
  (307, 'ॐ द्यौः पिता', 'Om Dyauh Pita', 'Om — Sky Father.', 'universal', 'Sky', 'OHM dyow PIH-tah', 'om_dyauh_pita.mp3', 'https://paulwagner.com', 'Sky and earth: the universal parents →', 'The sky as father — the vast, open awareness that contains all experience. The earth is our mother; the sky is our father. We are children of both.', 'flower_of_life'),
  (308, 'ॐ अन्तरिक्षम्', 'Om Antariksha', 'Om — the space between — the intermediate realm.', 'universal', 'Space', 'OHM ahn-TAH-rik-shahm', 'om_antariksha.mp3', 'https://paulwagner.com', 'The space between: where transformation happens →', 'Antariksha — "the space between" — is the intermediate realm between earth and sky. It represents the liminal space of transformation.', 'seed_of_life'),
  (309, '', 'The deeper I go, the freer I become', 'The deeper I go, the freer I become', 'universal', 'Growth', '', '', 'https://paulwagner.com', 'Transforming obstacles into awakening →', 'The soul does not grow in comfort — it grows in the fire of transformation. Every difficulty is grace in disguise.', 'seed_of_life'),
  (310, '', 'My shame is an imagined prison — dissolved', 'My shame is an imagined prison — dissolved', 'universal', 'Gratitude', '', '', 'https://paulwagner.com', 'The transformative power of gratitude →', 'Gratitude is not just a feeling — it is a frequency. When you vibrate with thankfulness, the entire universe conspires in your favor.', 'seed_of_life'),
  (311, '', 'I owe the past exactly nothing', 'I owe the past exactly nothing', 'universal', 'Compassion', '', '', 'https://paulwagner.com', 'The ripple effect of compassion →', 'When you send love outward, it multiplies and returns to you a thousandfold. This is the law of the heart.', 'lotus'),
  (312, '', 'I release the debt ledger permanently', 'I release the debt ledger permanently', 'universal', 'Body Reverence', '', '', 'https://paulwagner.com', 'The body as spiritual technology →', 'Your body is not separate from spirit — it is spirit made visible. Treat it with the reverence it deserves.', 'lotus'),
  (313, '', 'Head to the forest — scream with abandon', 'Head to the forest — scream with abandon', 'universal', 'Equanimity', '', '', 'https://paulwagner.com', 'Finding your unshakable center →', 'The ocean\'s surface may rage, but its depths remain forever still. You are that depth.', 'lotus'),
  (314, '', 'Surrender everything — She is far more capable', 'Surrender everything — She is far more capable', 'universal', 'Healing', '', '', 'https://paulwagner.com', 'The body\'s innate wisdom to heal →', 'Healing is not something that happens to you — it is something that happens through you when you stop resisting the flow of grace.', 'lotus'),
  (315, '', 'Control is futile — I consent to the flow', 'Control is futile — I consent to the flow', 'universal', 'Truth', '', '', 'https://paulwagner.com', 'Living in radical truth →', 'Truth is not a concept — it is a vibration. When you live in alignment with truth, every part of your life begins to harmonize.', 'sri_yantra'),
  (316, '', 'I lay my burdens at Her feet', 'I lay my burdens at Her feet', 'universal', 'Grace', '', '', 'https://paulwagner.com', 'Becoming a vessel for grace →', 'You do not need to generate grace — you need only to stop blocking it. Remove the resistance, and grace floods in.', 'sri_yantra'),
  (317, '', 'I pray like my soul depends on it', 'I pray like my soul depends on it', 'universal', 'Transformation', '', '', 'https://paulwagner.com', 'The alchemy of suffering →', 'Your deepest pain holds your greatest teaching. The soul chose these experiences not to punish you, but to awaken you.', 'sri_yantra'),
  (318, 'ॐ लोकाः समस्ताः सुखिनो भवन्तु', 'Om Lokah Samastah Sukhino Bhavantu', 'Om — may all beings in all worlds be happy and free.', 'universal', 'Universal Welfare', 'OHM LOH-kah sah-MAHS-tah soo-KHIH-noh bhah-VAHN-too', 'om_lokah_samastah_su.mp3', 'https://paulwagner.com', 'Lokah Samastah: the prayer that changes the world →', 'The most universal of all mantras. Lokah — "worlds" — Samastah — "all." This prayer extends to all beings in all dimensions of existence.', 'lotus'),
  (319, '', 'I am not the mayhem — I am potential', 'I am not the mayhem — I am potential', 'universal', 'Self-Realization', '', '', 'https://paulwagner.com', 'The Vedantic truth of who you are →', 'This is the core teaching of Vedanta — you are Brahman, the absolute reality. Everything else is appearance.', 'lotus'),
  (320, '', 'Grace is my birthright — not earned, claimed', 'Grace is my birthright — not earned, claimed', 'universal', 'Inner Guidance', '', '', 'https://paulwagner.com', 'Listening to your soul\'s wisdom →', 'Your soul has walked a thousand lifetimes. It knows things your mind cannot fathom. Learn to listen.', 'lotus'),
  (321, '', 'I let The Divine see me naked', 'I let The Divine see me naked', 'universal', 'Faith', '', '', 'https://paulwagner.com', 'The difference between belief and faith →', 'Faith is not believing without evidence — it is trusting the evidence of your own direct experience of the divine.', 'lotus'),
  (322, '', 'I consecrate my life — or keep suffering', 'I consecrate my life — or keep suffering', 'universal', 'Joy', '', '', 'https://paulwagner.com', 'Reclaiming your birthright of joy →', 'Joy is not frivolous — it is your natural state. The guilt around joy is a learned pattern, not a spiritual truth.', 'lotus'),
  (323, 'ॐ ह्रीं', 'Om Hrim', 'Om — the maya bija — the seed of divine power.', 'universal', 'Power', 'OHM hreem', 'om_hrim.mp3', 'https://paulwagner.com', 'Hrim: the seed syllable of the goddess →', 'Hrim is the bija (seed syllable) of the goddess — the sound of maya, the creative power of the divine. It is the most powerful single syllable after Om.', 'lotus'),
  (324, 'ॐ श्रीं', 'Om Shrim', 'Om — the Lakshmi bija — the seed of abundance.', 'universal', 'Abundance', 'OHM shreem', 'om_shrim.mp3', 'https://paulwagner.com', 'Shrim: the sound of abundance →', 'Shrim is the bija of Lakshmi — the sound of abundance, beauty, and grace. It attracts all forms of prosperity: material, emotional, and spiritual.', 'lotus'),
  (325, 'ॐ ऐं', 'Om Aim', 'Om — the Saraswati bija — the seed of wisdom.', 'universal', 'Wisdom', 'OHM aim (rhymes with "time")', 'om_aim.mp3', 'https://paulwagner.com', 'Aim: the seed syllable of wisdom →', 'Aim is the bija of Saraswati — the sound of wisdom, learning, and creative intelligence. It activates the higher mind.', 'lotus'),
  (326, 'ॐ क्लीं', 'Om Klim', 'Om — the Kama bija — the seed of love and attraction.', 'universal', 'Love', 'OHM kleem', 'om_klim.mp3', 'https://paulwagner.com', 'Klim: the seed syllable of divine love →', 'Klim is the bija of Kama — divine love and attraction. It draws all good things toward you and opens the heart to love.', 'lotus'),
  (327, 'ॐ क्रीं', 'Om Krim', 'Om — the Kali bija — the seed of transformation.', 'universal', 'Transformation', 'OHM kreem', 'om_krim.mp3', 'https://paulwagner.com', 'Krim: the seed syllable of transformation →', 'Krim is the bija of Kali — the sound of radical transformation. It destroys what is false and reveals what is true.', 'lotus'),
  (328, 'ॐ हूँ', 'Om Hum', 'Om — the Shiva bija — the seed of fire and protection.', 'universal', 'Protection', 'OHM hoom', 'om_hum.mp3', 'https://paulwagner.com', 'Hum: the seed syllable of fire and protection →', 'Hum is the bija of Shiva — the sound of fire, protection, and the destruction of obstacles. It is also the seed of the awakened mind in Buddhism.', 'sri_yantra'),
  (329, 'ॐ फट्', 'Om Phat', 'Om — the weapon bija — the sound that cuts through all obstacles.', 'universal', 'Cutting Through', 'OHM phaht (sharp, explosive)', 'om_phat.mp3', 'https://paulwagner.com', 'The weapon mantras: cutting through obstacles →', 'Phat is the weapon bija — the sound of a sword cutting through obstacles. It is used at the end of protective mantras to seal and strengthen them.', 'sri_yantra'),
  (330, 'ॐ स्वाहा', 'Om Svaha', 'Om — so be it — I offer this.', 'universal', 'Offering', 'OHM svah-HAH', 'om_svaha.mp3', 'https://paulwagner.com', 'Svaha: the sound of sacred offering →', 'Svaha is the offering bija — the sound of fire sacrifice. It seals all offerings and prayers, surrendering them to the divine.', 'flower_of_life'),
  (331, 'ॐ नमः', 'Om Namah', 'Om — I bow — I offer myself.', 'universal', 'Surrender', 'OHM nah-MAH', 'om_namah.mp3', 'https://paulwagner.com', 'Namah: the power of bowing →', 'Namah — "I bow" — is the most universal act of spiritual surrender. It is the recognition that the divine is greater than the ego.', 'flower_of_life'),
  (332, 'ॐ नमस्ते', 'Om Namaste', 'Om — I bow to the divine in you.', 'universal', 'Recognition', 'OHM nah-mahs-TAY', 'om_namaste.mp3', 'https://paulwagner.com', 'Namaste: the greeting that changes how you see the world →', 'Namaste — "I bow to the divine in you" — is the recognition that every being is a form of the divine. This is the most radical spiritual teaching.', 'flower_of_life'),
  (333, 'ॐ तत् त्वम् असि', 'Om Tat Tvam Asi', 'Om — that thou art — you are the infinite.', 'universal', 'Non-Duality', 'OHM taht tvahm AH-see', 'om_tat_tvam_asi.mp3', 'https://paulwagner.com', 'The teacher-student relationship in non-dual wisdom →', 'Day 333 — a triple number — for the triple teaching: the teacher (Tat), the student (Tvam), and the identity between them (Asi).', 'sri_yantra'),
  (334, 'ॐ अयम् आत्मा ब्रह्म', 'Om Ayam Atma Brahma', 'Om — this self is Brahman.', 'universal', 'Self-Realization', 'OHM AH-yahm AHT-mah BRAH-mah', 'om_ayam_atma_brahma.mp3', 'https://paulwagner.com', 'The Mandukya Upanishad: the shortest and deepest Upanishad →', 'The Mandukya Upanishad mahavakya. This self — the one reading these words right now — is the infinite. Not after enlightenment. Now.', 'sri_yantra'),
  (335, 'ॐ प्रज्ञानं ब्रह्म', 'Om Prajnanam Brahma', 'Om — consciousness is Brahman.', 'universal', 'Consciousness', 'OHM PRAHJ-nyah-nahm BRAH-mah', 'om_prajnanam_brahma.mp3', 'https://paulwagner.com', 'Consciousness: the hard problem and the Upanishadic answer →', 'The Aitareya Upanishad mahavakya. The very awareness that is reading these words is the infinite. Consciousness is not produced by the brain — it is the ground of being.', 'sri_yantra'),
  (336, 'ॐ अहम् ब्रह्मास्मि', 'Om Aham Brahmasmi', 'Om — I am Brahman.', 'universal', 'Identity', 'OHM AH-hahm BRAH-mahs-mih', 'om_aham_brahmasmi.mp3', 'https://paulwagner.com', 'Aham Brahmasmi: the most radical statement in human history →', 'The Brihadaranyaka Upanishad mahavakya. The most direct declaration of identity with the infinite. Not a belief — a recognition.', 'sri_yantra'),
  (337, '', 'When I pray, The Universe prays for me', 'When I pray, The Universe prays for me', 'universal', 'Self-Love', '', '', 'https://paulwagner.com', 'The inner beloved awakens →', 'The greatest love story is the one between you and your own soul. Stop searching outside for what has always been within.', 'sri_yantra'),
  (338, '', 'Sound moves matter — mantra moves consciousness', 'Sound moves matter — mantra moves consciousness', 'universal', 'Surrender', '', '', 'https://paulwagner.com', 'The freedom in letting go →', 'Control is the mind\'s attempt to manage fear. Surrender is the soul\'s invitation to dance with the divine.', 'sri_yantra'),
  (339, 'ॐ नित्यानन्द', 'Om Nityananda', 'Om — eternal bliss.', 'universal', 'Bliss', 'OHM nih-TYAH-nahn-dah', 'om_nityananda.mp3', 'https://paulwagner.com', 'Nityananda: the eternal bliss that is your nature →', 'Nityananda — "eternal bliss" — is the name of several great masters. It points to the bliss that is the natural state of the self, not dependent on circumstances.', 'seed_of_life'),
  (340, 'ॐ परमानन्द', 'Om Paramananda', 'Om — supreme bliss.', 'universal', 'Supreme Joy', 'OHM pah-rah-MAH-nahn-dah', 'om_paramananda.mp3', 'https://paulwagner.com', 'Ananda: the bliss that is the nature of the self →', 'Paramananda — "supreme bliss" — is the highest state of consciousness. It is not an experience that comes and goes but the very nature of pure awareness.', 'seed_of_life'),
  (341, 'ॐ सोऽहम् सोऽहम् सोऽहम्', 'Om Soham Soham Soham', 'Om — I am that, I am that, I am that.', 'universal', 'Identity', 'OHM SOH-hahm SOH-hahm SOH-hahm', 'om_soham_soham_soham.mp3', 'https://paulwagner.com', 'The breath as the teacher: the Soham practice →', 'Triple Soham — the breath mantra repeated three times to deepen the recognition. With every breath, the universe is saying: "I am that."', 'seed_of_life'),
  (342, '', 'I am a wild light — vast and unbound', 'I am a wild light — vast and unbound', 'universal', 'Wonder', '', '', 'https://paulwagner.com', 'You are made of stardust — literally →', 'This is not metaphor — this is physics. The iron in your blood, the calcium in your bones, all of it was born in stellar furnaces billions of years ago.', 'sri_yantra'),
  (343, '', 'I Am That — Tat Tvam Asi', 'I Am That — Tat Tvam Asi', 'universal', 'Presence', '', '', 'https://paulwagner.com', 'The power of conscious presence →', 'The most powerful thing you can bring to any situation is your full, undivided presence. It is the rarest gift in the modern world.', 'sri_yantra'),
  (344, '', 'I am divine electricity born of light', 'I am divine electricity born of light', 'universal', 'Liberation', '', '', 'https://paulwagner.com', 'Breaking free from karmic patterns →', 'You are not your history. You are the awareness that can observe that history and choose a different path forward.', 'sri_yantra'),
  (345, '', 'Liberation isn\'t achieved — it\'s remembered', 'Liberation isn\'t achieved — it\'s remembered', 'universal', 'Integration', '', '', 'https://paulwagner.com', 'Shadow work as spiritual practice →', 'The parts of yourself you reject become the chains that bind you. The parts you embrace become the wings that free you.', 'sri_yantra'),
  (346, '', 'I am not seeking freedom — I am freedom', 'I am not seeking freedom — I am freedom', 'universal', 'Meditation', '', '', 'https://paulwagner.com', 'The space between thoughts →', 'Meditation is not about stopping thoughts — it is about discovering the vast silence that was always there, holding every thought like the sky holds clouds.', 'seed_of_life'),
  (347, '', 'I am whole, covered in removable layers', 'I am whole, covered in removable layers', 'universal', 'Rest', '', '', 'https://paulwagner.com', 'The spiritual necessity of rest →', 'In a world that glorifies hustle, choosing rest is a radical act of self-love. Your soul needs space to integrate and renew.', 'seed_of_life'),
  (348, '', 'I was born through The Universe loving Itself', 'I was born through The Universe loving Itself', 'universal', 'Authenticity', '', '', 'https://paulwagner.com', 'The courage of radical openness →', 'The spiritual warrior does not hide behind walls — they stand in the open field of their own heart, undefended and unafraid.', 'seed_of_life'),
  (349, '', 'I am unlimited in every direction — no exceptions', 'I am unlimited in every direction — no exceptions', 'universal', 'Trust', '', '', 'https://paulwagner.com', 'Trusting your soul\'s perfect timing →', 'There are no wrong turns on the soul\'s journey. Every detour was a necessary lesson. You are right on time.', 'flower_of_life'),
  (350, '', 'My emptiness is consciousness awaiting freedom', 'My emptiness is consciousness awaiting freedom', 'universal', 'Transmutation', '', '', 'https://paulwagner.com', 'Breathwork as emotional alchemy →', 'The breath is the most powerful tool for emotional alchemy. Use it consciously and watch your inner world transform.', 'flower_of_life'),
  (351, '', 'I am the source and the signal', 'I am the source and the signal', 'universal', 'Perspective', '', '', 'https://paulwagner.com', 'The ocean of consciousness →', 'This is the essence of Vedantic teaching — you are not the passing phenomena, you are the eternal substrate upon which all phenomena arise.', 'flower_of_life'),
  (352, '', 'I stop pretending — I remember who I am', 'I stop pretending — I remember who I am', 'universal', 'Self-Honor', '', '', 'https://paulwagner.com', 'Their highlight reel vs your raw footage →', 'Comparison is the thief of joy and the enemy of spiritual growth. Your soul chose this exact path for reasons only it understands.', 'flower_of_life'),
  (353, 'ॐ नमो गुरवे', 'Om Namo Gurave', 'Om — I bow to the Guru.', 'universal', 'Gratitude', 'OHM nah-MOH GOO-rah-vay', 'om_namo_gurave.mp3', 'https://paulwagner.com', 'The Guru principle: beyond the personal teacher →', 'A simple, direct bow to the teacher. The Guru is not a person — the Guru is the principle of awakening that appears in many forms.', 'flower_of_life'),
  (354, 'ॐ महावीराय नमः', 'Om Mahaviraya Hanumante Namah', 'Om, I bow to the great hero Hanuman.', 'vedic_vishnu', 'Heroism', 'OHM mah-hah-VEE-rah-yah hah-noo-MAHN-tay nah-MAH', 'mantra-354.mp3', 'https://paulwagner.com', 'Mahavira: the great hero within you →', 'Mahavira — "great hero" — Hanuman is the supreme example of heroism born from devotion. His strength came not from ego but from love for Rama. True heroism is selfless service.', 'flower_of_life'),
  (355, 'ॐ आञ्जनेयाय नमः', 'Om Anjaneyaya Namah', 'Om, I bow to the son of Anjana — Hanuman the mighty.', 'vedic_vishnu', 'Strength', 'OHM ahn-jah-NAY-yah-yah nah-MAH', 'mantra-355.mp3', 'https://paulwagner.com', 'The leap of faith: Hanuman crosses the ocean →', 'Anjaneya — "son of Anjana" — Hanuman leaped across the ocean to find Sita. When devotion is total, no obstacle is too great. This mantra invokes unstoppable strength.', 'seed_of_life'),
  (356, '', 'Faking it is a spiritual disease', 'Faking it is a spiritual disease', 'universal', 'Wonder', '', '', 'https://paulwagner.com', 'The miracle of your existence →', 'The probability of you existing exactly as you are is essentially zero — and yet here you are. You are the universe\'s way of knowing itself.', 'lotus'),
  (357, 'ॐ वायुपुत्राय नमः', 'Om Vayuputraya Namah', 'Om, I bow to the son of the wind — Hanuman the swift.', 'vedic_vishnu', 'Speed', 'OHM vah-yoo-POOT-rah-yah nah-MAH', 'mantra-357.mp3', 'https://paulwagner.com', 'Vayu: the wind god and father of Hanuman →', 'Vayuputra — "son of the wind" — Hanuman inherited the speed and power of Vayu, the wind god. This mantra invokes swift action and the breath of life itself.', 'flower_of_life'),
  (358, 'मृत्योर्मा अमृतं गमय ॐ शान्तिः शान्तिः शान्तिः', 'Mrityorma Amritam Gamaya Om Shantih Shantih Shantih', 'Lead me from death to immortality — Om peace, peace, peace.', 'universal', 'Immortality', 'mrih-TYOR-mah AHM-rih-tahm GAH-mah-yah OHM SHAHN-tih SHAHN-tih SHAHN-tih', 'mrityorma_amritam_ga.mp3', 'https://paulwagner.com', 'The complete Pavamana Mantra: a year-end practice →', 'The complete Pavamana Mantra with its closing peace invocation. The three prayers and the three peaces — a complete practice.', 'sri_yantra'),
  (359, '', 'I rip the mask off my polite spiritual act', 'I rip the mask off my polite spiritual act', 'universal', 'Wholeness', '', '', 'https://paulwagner.com', 'Remembering your original wholeness →', 'The word \'holy\' comes from the same root as \'whole.\' To be holy is simply to be complete — and you already are.', 'seed_of_life'),
  (360, '', 'My fire is not an obstacle — it\'s fuel', 'My fire is not an obstacle — it\'s fuel', 'universal', 'Namaste', '', '', 'https://paulwagner.com', 'Seeing the divine in everyone →', 'Namaste in action — recognizing the divine in every face you encounter. Their light does not diminish yours; it amplifies it.', 'seed_of_life'),
  (361, '', 'I let the world fall apart — I stay real', 'I let the world fall apart — I stay real', 'universal', 'Self-Knowledge', '', '', 'https://paulwagner.com', 'Sat-Chit-Ananda: your true nature →', 'This is the English expression of the highest Vedantic truth. You are not seeking bliss — you ARE bliss, temporarily forgetting itself.', 'sri_yantra'),
  (362, 'ॐ शिवोऽहम् शिवोऽहम्', 'Om Shivoham Shivoham', 'Om — I am Shiva, I am Shiva.', 'universal', 'Identity', 'OHM shih-VOH-hahm shih-VOH-hahm', 'om_shivoham_shivoham.mp3', 'https://paulwagner.com', 'The recognition that deepens with practice →', 'Day 362 — four days from the end. The recognition deepens: not just "I am that" but "I am Shiva" — pure consciousness, pure bliss, pure awareness.', 'sri_yantra'),
  (363, '', 'I am done shrinking for anyone\'s comfort', 'I am done shrinking for anyone\'s comfort', 'universal', 'Being', '', '', 'https://paulwagner.com', 'The power of pure being →', 'The most ancient declaration of truth, found in every wisdom tradition. Not I am this or that — simply I AM.', 'sri_yantra'),
  (364, '', 'I speak like I\'m casting my next incarnation', 'I speak like I\'m casting my next incarnation', 'universal', 'Renewal', '', '', 'https://paulwagner.com', 'The gift of new beginnings →', 'Every sunrise is an invitation to start fresh. No matter what yesterday held, today you can choose love again.', 'lotus'),
  (365, '', 'Every word is a boomerang — I speak liberation', 'Every word is a boomerang — I speak liberation', 'universal', 'Completion', '', '', 'https://paulwagner.com', 'The journey home to yourself →', 'The final mantra of the year — a recognition that the entire journey was a circle leading you back to yourself. You are home.', 'seed_of_life');
